      <path d="M${x + 30} ${y + 29} C${x + 38} ${y + 12} ${x + 45} ${y + 38} ${x + 55} ${y + 18}" fill="none" stroke="${escapeXml(accent)}" stroke-width="2" stroke-linecap="round" opacity="0.72" />
