/** A one-draw, one-surface flame seed for a held charge. Every vertex belongs
 * to the same closed sphere topology: stretching and bending that topology
 * creates the hook, shoulder, and deep body without intersecting cone shells
 * or the hard origami seams those overlaps produced in review. */
export function createPfxFlameChargeCrucibleGeometry(): THREE.BufferGeometry {
  const smoothRadialSegments = 48
  const smoothHeightSegments = 32
  const coreRadius = 0.42
  const geometry = new THREE.SphereGeometry(coreRadius, smoothRadialSegments, smoothHeightSegments)
  const position = geometry.getAttribute('position')
  const point = new THREE.Vector3()
  const direction = new THREE.Vector3()
  const crestOffset = 0.3
  const crestDepthOffset = -0.3
  const crestLift = 0.55
  const secondaryLobeDirection = new THREE.Vector3(-0.64, 0.18, 0.75).normalize()
  for (let index = 0; index < position.count; index += 1) {
    point.fromBufferAttribute(position, index)
    direction.copy(point).normalize()
    const upper = THREE.MathUtils.smoothstep(direction.y, -0.12, 0.98)
    const crest = Math.pow(upper, 1.72)
    const lower = THREE.MathUtils.smoothstep(-direction.y, 0.35, 1)
    const secondaryLobe = Math.pow(
      THREE.MathUtils.smoothstep(direction.dot(secondaryLobeDirection), 0.3, 0.94),
      1.5,
    )
    const organicRadius = 1
      + Math.sin(direction.x * 8.7 + direction.y * 5.1 + direction.z * 3.9) * 0.045
      + Math.sin(direction.z * 11.3 - direction.y * 7.4) * 0.022
      + secondaryLobe * 0.16
    point.multiplyScalar(organicRadius)
    point.x *= 0.78 * (1 - crest * 0.5) * (1 - lower * 0.06)
    point.z *= 1.85 * (1 - crest * 0.78) * (1 - lower * 0.04)
    point.y *= 0.98
    // One dominant crest bends through X and Z, while the continuous
    // secondary shoulder broadens the opposite depth quadrant below it.
    point.x += crest * crestOffset - secondaryLobe * 0.055
    point.z += crest * crestDepthOffset + secondaryLobe * 0.075
    point.y += crest * crestLift + secondaryLobe * 0.07
    position.setXYZ(index, point.x, point.y, point.z)
  }
  position.needsUpdate = true
  geometry.computeVertexNormals()
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxFlameChargeCrucible'] = 'single-draw-continuous-bent-flame-volume'
  geometry.userData['pfxFlameChargeDrawCalls'] = 1
  geometry.userData['pfxFlameChargeContinuousSurface'] = true
  geometry.userData['pfxFlameChargeInterlockingVolumes'] = false
  geometry.userData['pfxFlameChargeSmoothRadialSegments'] = smoothRadialSegments
  geometry.userData['pfxFlameChargeSmoothHeightSegments'] = smoothHeightSegments
  geometry.userData['pfxFlameChargeCoreRadius'] = coreRadius
  geometry.userData['pfxFlameChargeBentCrest'] = true
  geometry.userData['pfxFlameChargeCrestOffset'] = crestOffset
  geometry.userData['pfxFlameChargeCrestDepthOffset'] = crestDepthOffset
  geometry.userData['pfxFlameChargeCrestLift'] = crestLift
  geometry.userData['pfxFlameChargeSecondaryDepthLobe'] = true
  geometry.userData['pfxFlameChargeSecondaryLobeDirectionZ'] = secondaryLobeDirection.z
  geometry.userData['pfxFlameChargeCrossSectionAspect'] =
    (geometry.boundingBox!.max.z - geometry.boundingBox!.min.z) /
    Math.max(0.001, geometry.boundingBox!.max.x - geometry.boundingBox!.min.x)
  geometry.userData['pfxFlameChargeConnectedComponents'] = 1
  geometry.userData['pfxFlameChargeLargestComponentShare'] = 1
  geometry.userData['pfxFlameChargeDominantContinuousBody'] = true
  geometry.userData['pfxFlameChargeVolumeAxis'] = 'y'
  geometry.userData['pfxFlameChargeForwardSpan'] = geometry.boundingBox!.max.x - geometry.boundingBox!.min.x
  geometry.userData['pfxFlameChargeNonCircularCrossSection'] = true
  geometry.userData['pfxFlameChargeRadialSymmetry'] = false
  geometry.userData['pfxFlameChargeHeightSpan'] = geometry.boundingBox!.max.y - geometry.boundingBox!.min.y
  geometry.userData['pfxFlameChargeClosedCaps'] = true
  geometry.userData['pfxFlameChargeDepthSpan'] = geometry.boundingBox!.max.z - geometry.boundingBox!.min.z
  return geometry
}

/** Four unequal fuel streams curl through real depth before entering the
 * held flame core. Narrow crossed ribbons preserve parallax without the
 * bulbous mouths of tubes, repeated sprite cards, or cable-heavy silhouettes. */
export function createPfxFlameChargeTendrilGeometry(): THREE.BufferGeometry {
  const tendrilCount = 4
  const tubularSegments = 48
  const ribbonPlaneCount = tendrilCount * 2
  const outerRadii = [0.82, 0.68, 0.76, 0.72]
  const outerRadius = Math.max(...outerRadii)
  const terminalRadius = 0.13
  const laneSweeps = [Math.PI * 0.28, -Math.PI * 0.34, Math.PI * 0.22, -Math.PI * 0.3]
  const arcSweep = Math.max(...laneSweeps.map(Math.abs))
  const laneHalfWidths = [0.086, 0.074, 0.08, 0.068]
  const maximumHalfWidth = Math.max(...laneHalfWidths)
  const outerEndpointScale = 0
  const innerEndpointScale = 0.34
  const lanePhases = [-2.65, -0.9, 0.55, 2.18]
  const outerHeights = [-0.34, 0.29, 0.06, 0.45]
  const terminalHeights = [-0.06, 0.04, 0.02, 0.08]
  const laneLifts = [0.11, -0.09, 0.13, -0.12]
  const positions: number[] = []
  const normals: number[] = []
  const uvs: number[] = []
  const flowProgress: number[] = []
  const laneIndices: number[] = []
  const indices: number[] = []
  const center = new THREE.Vector3()
  const tangent = new THREE.Vector3()
  const axis = new THREE.Vector3()
  const faceNormal = new THREE.Vector3()
  const vertex = new THREE.Vector3()

  for (let lane = 0; lane < tendrilCount; lane += 1) {
    const phase = lanePhases[lane]!
    const points = Array.from({ length: 8 }, (_, pointIndex) => {
      const progress = pointIndex / 7
      const eased = progress * progress * (3 - 2 * progress)
      const radius = THREE.MathUtils.lerp(outerRadii[lane]!, terminalRadius, eased)
      const angle = phase + progress * laneSweeps[lane]!
      const lift = Math.sin(progress * Math.PI) * laneLifts[lane]!
      return new THREE.Vector3(
        Math.cos(angle) * radius,
        THREE.MathUtils.lerp(outerHeights[lane]!, terminalHeights[lane]!, eased) + lift,
        Math.sin(angle) * radius * 0.84,
      )
    })
    const curve = new THREE.CatmullRomCurve3(points, false, 'centripetal', 0.5)
    const frames = curve.computeFrenetFrames(tubularSegments, false)
    for (let plane = 0; plane < 2; plane += 1) {
      const baseVertex = positions.length / 3
      for (let segment = 0; segment <= tubularSegments; segment += 1) {
        const progress = segment / tubularSegments
        curve.getPointAt(progress, center)
        curve.getTangentAt(progress, tangent).normalize()
        axis.copy(plane === 0 ? frames.normals[segment]! : frames.binormals[segment]!).normalize()
        faceNormal.crossVectors(tangent, axis).normalize()
        const outerGrowth = THREE.MathUtils.smoothstep(progress, 0, 0.16)
        const coreAttachment = THREE.MathUtils.lerp(
          1,
          innerEndpointScale,
          THREE.MathUtils.smoothstep(progress, 0.72, 1),
        )
        const taper = outerGrowth * coreAttachment
        const width = taper * laneHalfWidths[lane]!
          * (0.9 + Math.sin(progress * 16 + lane * 2.1 + plane * 1.4) * 0.1)
        for (let side = 0; side < 2; side += 1) {
          const signedWidth = side === 0 ? -width : width
          vertex.copy(center).addScaledVector(axis, signedWidth)
          positions.push(vertex.x, vertex.y, vertex.z)
          normals.push(faceNormal.x, faceNormal.y, faceNormal.z)
          uvs.push(progress, side)
          flowProgress.push(progress)
          laneIndices.push(lane)
        }
      }
      for (let segment = 0; segment < tubularSegments; segment += 1) {
        const start = baseVertex + segment * 2
        const next = start + 2
        indices.push(start, start + 1, next, start + 1, next + 1, next)
      }
    }
  }

  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.setAttribute('aFlowProgress', new THREE.Float32BufferAttribute(flowProgress, 1))
  geometry.setAttribute('aTendrilLane', new THREE.Float32BufferAttribute(laneIndices, 1))
  geometry.setIndex(indices)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxFlameChargeTendrils'] = 'four-narrow-crossed-inward-fire-ribbons'
  geometry.userData['pfxFlameChargeTendrilCount'] = tendrilCount
  geometry.userData['pfxFlameChargeRibbonPlaneCount'] = ribbonPlaneCount
  geometry.userData['pfxFlameChargeTendrilAsymmetricLanes'] = true
  geometry.userData['pfxFlameChargeVolumetricCrossedRibbons'] = true
  geometry.userData['pfxFlameChargeTendrilDrawCalls'] = 1
  geometry.userData['pfxFlameChargeTendrilTapered'] = true
  geometry.userData['pfxFlameChargeTendrilOuterEndpointScale'] = outerEndpointScale
  geometry.userData['pfxFlameChargeTendrilInnerEndpointScale'] = innerEndpointScale
  geometry.userData['pfxFlameChargeTendrilOuterRadius'] = outerRadius
  geometry.userData['pfxFlameChargeTendrilTerminalRadius'] = terminalRadius
  geometry.userData['pfxFlameChargeTendrilMaximumHalfWidth'] = maximumHalfWidth
  geometry.userData['pfxFlameChargeTendrilArcSweep'] = arcSweep
  geometry.userData['pfxFlameChargeTendrilDepthSpan'] = geometry.boundingBox!.max.z - geometry.boundingBox!.min.z
  geometry.userData['pfxFlameChargeTendrilHeightSpan'] = geometry.boundingBox!.max.y - geometry.boundingBox!.min.y
  return geometry
}

/** A single grounded draw combines the impact bowl, embedded meteor, and
 * irregular lifted rim rocks. Vertex colors keep the center incandescent and
 * the broken outer lip dark without multiplying materials on mobile. */
export function createPfxMeteorImpactGeometry(): THREE.BufferGeometry {
  const geometries: THREE.BufferGeometry[] = []
  const ensureNonIndexed = (geometry: THREE.BufferGeometry) => (
    geometry.index ? geometry.toNonIndexed() : geometry
  )
  const assignColors = (
    geometry: THREE.BufferGeometry,
    colorAt: (point: THREE.Vector3, index: number) => THREE.Color,
  ) => {
    geometry.deleteAttribute('uv')
    const position = geometry.getAttribute('position')
    const colors = new Float32Array(position.count * 3)
    const point = new THREE.Vector3()
    for (let index = 0; index < position.count; index += 1) {
      point.fromBufferAttribute(position, index)
      const color = colorAt(point, index)
      colors[index * 3] = color.r
      colors[index * 3 + 1] = color.g
      colors[index * 3 + 2] = color.b
    }
    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3))
    geometry.computeVertexNormals()
    return geometry
  }

  const bowlPositions: number[] = [0, -0.055, 0]
  const bowlIndices: number[] = []
  const radialSegments = 36
  const rings = [
    { radius: 0.18, height: -0.035 },
    { radius: 0.38, height: -0.01 },
    { radius: 0.58, height: 0.02 },
    { radius: 0.72, height: 0.055 },
  ]
  for (const [ringIndex, ring] of rings.entries()) {
    for (let segment = 0; segment < radialSegments; segment += 1) {
      const angle = segment / radialSegments * Math.PI * 2
      const irregular = 1 + Math.sin(angle * 5 + ringIndex * 0.8) * 0.045 + Math.sin(angle * 9 - 0.4) * 0.018
      bowlPositions.push(
        Math.cos(angle) * ring.radius * irregular,
        ring.height + Math.sin(angle * 7 + ringIndex) * 0.012,
        Math.sin(angle) * ring.radius * irregular,
      )
    }
  }
  for (let segment = 0; segment < radialSegments; segment += 1) {
    const next = (segment + 1) % radialSegments
    bowlIndices.push(0, 1 + next, 1 + segment)
  }
  for (let ringIndex = 0; ringIndex < rings.length - 1; ringIndex += 1) {
    const innerStart = 1 + ringIndex * radialSegments
    const outerStart = innerStart + radialSegments
    for (let segment = 0; segment < radialSegments; segment += 1) {
      const next = (segment + 1) % radialSegments
      bowlIndices.push(
        innerStart + segment, outerStart + next, outerStart + segment,
        innerStart + segment, innerStart + next, outerStart + next,
      )
    }
  }
  const bowlSource = new THREE.BufferGeometry()
  bowlSource.setAttribute('position', new THREE.Float32BufferAttribute(bowlPositions, 3))
  bowlSource.setIndex(bowlIndices)
  const bowl = ensureNonIndexed(bowlSource)
  bowlSource.dispose()
  assignColors(bowl, (vertex) => {
    const radius = Math.hypot(vertex.x, vertex.z)
    const angle = Math.atan2(vertex.z, vertex.x)
    const heat = 1 - THREE.MathUtils.smoothstep(radius, 0.08, 0.72)
    const crackBand = THREE.MathUtils.smoothstep(radius, 0.16, 0.28) * (1 - THREE.MathUtils.smoothstep(radius, 0.58, 0.72))
    const radialCrack = Math.pow(1 - Math.abs(Math.sin(angle * 4 + 0.35)), 12) * crackBand
    const incandescent = THREE.MathUtils.clamp(heat * 0.66 + radialCrack * 0.92, 0, 1)
    return new THREE.Color('#240c08').lerp(new THREE.Color('#ff7918'), incandescent)
  })
  geometries.push(bowl)

  // A meteor *ring* needs a readable boundary beyond the crater mass. Keep
  // the band continuous, then use uneven radii and three darker heat notches
  // so it does not collapse into a stock torus or gameplay reticle.
  const boundarySegmentCount = 28
  const boundaryHeatNotches = new Set([3, 12, 21])
  const boundaryPositions: number[] = []
  const boundaryIndices: number[] = []
  for (let segment = 0; segment < boundarySegmentCount; segment += 1) {
    const next = (segment + 1) % boundarySegmentCount
    const angle = segment / boundarySegmentCount * Math.PI * 2
    const nextAngle = next / boundarySegmentCount * Math.PI * 2
    const innerRadius = 0.96 + Math.sin(angle * 3 + 0.6) * 0.008
    const nextInnerRadius = 0.96 + Math.sin(nextAngle * 3 + 0.6) * 0.008
    const outerRadius = 1.045 + Math.sin(angle * 5 - 0.35) * 0.012 + Math.sin(angle * 2) * 0.005
    const nextOuterRadius = 1.045 + Math.sin(nextAngle * 5 - 0.35) * 0.012 + Math.sin(nextAngle * 2) * 0.005
    const outerTop = 0.035 + Math.sin(angle * 4) * 0.015
    const nextOuterTop = 0.035 + Math.sin(nextAngle * 4) * 0.015
    const innerTop = 0.13 + Math.sin(angle * 3 + 0.45) * 0.042
    const nextInnerTop = 0.13 + Math.sin(nextAngle * 3 + 0.45) * 0.042
    const outerBottom = 0.005 + Math.sin(angle * 2) * 0.003
    const nextOuterBottom = 0.005 + Math.sin(nextAngle * 2) * 0.003
    const innerBottom = 0.02
    const base = boundaryPositions.length / 3
    boundaryPositions.push(
      Math.cos(angle) * outerRadius, outerTop, Math.sin(angle) * outerRadius,
      Math.cos(angle) * innerRadius, innerTop, Math.sin(angle) * innerRadius,
      Math.cos(nextAngle) * nextInnerRadius, nextInnerTop, Math.sin(nextAngle) * nextInnerRadius,
      Math.cos(nextAngle) * nextOuterRadius, nextOuterTop, Math.sin(nextAngle) * nextOuterRadius,
      Math.cos(angle) * outerRadius, outerBottom, Math.sin(angle) * outerRadius,
      Math.cos(angle) * innerRadius, innerBottom, Math.sin(angle) * innerRadius,
      Math.cos(nextAngle) * nextInnerRadius, innerBottom, Math.sin(nextAngle) * nextInnerRadius,
      Math.cos(nextAngle) * nextOuterRadius, nextOuterBottom, Math.sin(nextAngle) * nextOuterRadius,
    )
    boundaryIndices.push(
      base, base + 1, base + 2, base, base + 2, base + 3,
      base + 5, base + 6, base + 2, base + 5, base + 2, base + 1,
    )
  }
  const boundarySource = new THREE.BufferGeometry()
  boundarySource.setAttribute('position', new THREE.Float32BufferAttribute(boundaryPositions, 3))
  boundarySource.setIndex(boundaryIndices)
  const boundaryRing = ensureNonIndexed(boundarySource)
  boundarySource.dispose()
  assignColors(boundaryRing, (vertex) => {
    const radius = Math.hypot(vertex.x, vertex.z)
    const angle = Math.atan2(vertex.z, vertex.x)
    const normalizedAngle = (angle + Math.PI * 2) % (Math.PI * 2)
    const segment = Math.round(normalizedAngle / (Math.PI * 2) * boundarySegmentCount) % boundarySegmentCount
    const notch = boundaryHeatNotches.has(segment) ? 0.24 : 1
    const innerHeat = 1 - THREE.MathUtils.smoothstep(radius, 0.965, 1.045)
    const pulse = (0.62 + Math.sin(angle * 5 - 0.4) * 0.16 + Math.sin(angle * 2 + 0.8) * 0.1) * notch
    const heat = THREE.MathUtils.clamp(pulse * (0.28 + innerHeat * 0.92), 0, 1)
    return new THREE.Color('#260805').lerp(new THREE.Color('#ff6512'), heat)
  })
  geometries.push(boundaryRing)

  const lipSegmentCount = 24
  const lipPositions: number[] = []
  const lipIndices: number[] = []
  for (let segment = 0; segment < lipSegmentCount; segment += 1) {
    const angle = segment / lipSegmentCount * Math.PI * 2
    const outerRadius = 0.79 + Math.sin(angle * 5 + 0.7) * 0.045 + Math.sin(angle * 9 - 0.4) * 0.018
    const innerRadius = 0.62 + Math.sin(angle * 4 - 0.2) * 0.026
    const outerTop = 0.075 + Math.sin(angle * 7 + 0.3) * 0.055 + Math.sin(angle * 3) * 0.018
    const innerTop = 0.055 + Math.sin(angle * 6 - 0.4) * 0.026
    const outerBottom = -0.02 + Math.sin(angle * 5 + 0.2) * 0.014
    const innerBottom = 0.008 + Math.sin(angle * 4) * 0.01
    const cos = Math.cos(angle)
    const sin = Math.sin(angle)
    lipPositions.push(
      cos * outerRadius, outerTop, sin * outerRadius,
      cos * innerRadius, innerTop, sin * innerRadius,
      cos * outerRadius * 0.985, outerBottom, sin * outerRadius * 0.985,
      cos * innerRadius * 1.01, innerBottom, sin * innerRadius * 1.01,
    )
  }
  for (let segment = 0; segment < lipSegmentCount; segment += 1) {
    const next = (segment + 1) % lipSegmentCount
    const ot = segment * 4
    const it = ot + 1
    const ob = ot + 2
    const ib = ot + 3
    const nextOt = next * 4
    const nextIt = nextOt + 1
    const nextOb = nextOt + 2
    const nextIb = nextOt + 3
    lipIndices.push(
      it, nextIt, nextOt, it, nextOt, ot,
      ob, ot, nextOt, ob, nextOt, nextOb,
      ib, nextIt, it, ib, nextIb, nextIt,
    )
  }
  const craterLipSource = new THREE.BufferGeometry()
  craterLipSource.setAttribute('position', new THREE.Float32BufferAttribute(lipPositions, 3))
  craterLipSource.setIndex(lipIndices)
  const craterLip = ensureNonIndexed(craterLipSource)
  craterLipSource.dispose()
  assignColors(craterLip, (vertex) => {
    const radius = Math.hypot(vertex.x, vertex.z)
    const innerHeat = 1 - THREE.MathUtils.smoothstep(radius, 0.61, 0.8)
    return new THREE.Color('#170a08').lerp(new THREE.Color('#8b2008'), innerHeat * 0.76)
  })
  geometries.push(craterLip)

  const centerHeight = 0.1
  const meteorRadius = 0.27
  const meteor = ensureNonIndexed(new THREE.DodecahedronGeometry(meteorRadius, 0))
  meteor.scale(1.08, 0.56, 0.84)
  meteor.rotateX(0.12)
  meteor.rotateY(-0.34)
  meteor.rotateZ(0.18)
  const meteorOffset: readonly [number, number] = [0.16, -0.08]
  meteor.translate(meteorOffset[0], 0.06, meteorOffset[1])
  assignColors(meteor, (vertex, index) => {
    const faceBand = Math.floor(index / 3) % 7
    const palette = ['#1c0b09', '#35100a', '#f0520c', '#240c09', '#551307', '#ff8219', '#160a09']
    const color = new THREE.Color(palette[faceBand]!)
    return vertex.y < 0.03 ? color.multiplyScalar(0.72) : color
  })
  geometries.push(meteor)

  const rimRocks = [
    { angle: 0.08, radius: 0.69, size: 0.17, lift: 0.12, scale: [1.35, 0.72, 0.88], rotation: [0.2, 0.6, 0.1] },
    { angle: 0.74, radius: 0.73, size: 0.13, lift: 0.17, scale: [0.86, 1.18, 1.24], rotation: [0.7, 0.2, 0.5] },
    { angle: 1.5, radius: 0.67, size: 0.15, lift: 0.1, scale: [1.2, 0.66, 0.9], rotation: [0.3, 1.1, 0.2] },
    { angle: 2.22, radius: 0.75, size: 0.12, lift: 0.28, scale: [0.9, 1.4, 0.78], rotation: [0.9, 0.4, 0.7] },
    { angle: 3.04, radius: 0.68, size: 0.16, lift: 0.13, scale: [1.28, 0.7, 1.05], rotation: [0.45, 0.8, 0.3] },
    { angle: 3.86, radius: 0.72, size: 0.11, lift: 0.18, scale: [0.82, 1.3, 1.12], rotation: [1, 0.3, 0.6] },
    { angle: 4.58, radius: 0.66, size: 0.14, lift: 0.11, scale: [1.32, 0.64, 0.82], rotation: [0.25, 1.2, 0.4] },
    { angle: 5.42, radius: 0.74, size: 0.13, lift: 0.16, scale: [0.92, 1.16, 1.28], rotation: [0.8, 0.55, 0.9] },
  ] as const
  for (const [rockIndex, rock] of rimRocks.entries()) {
    const rockGeometry = ensureNonIndexed(rockIndex % 3 === 0
      ? new THREE.DodecahedronGeometry(rock.size, 0)
      : rockIndex % 3 === 1
        ? new THREE.IcosahedronGeometry(rock.size, 0)
        : new THREE.ConeGeometry(rock.size * 0.82, rock.size * 1.55, 5, 1))
    rockGeometry.scale(rock.scale[0] * 0.78, rock.scale[1] * 0.72, rock.scale[2] * 0.78)
    rockGeometry.rotateX(rock.rotation[0])
    rockGeometry.rotateY(rock.rotation[1])
    rockGeometry.rotateZ(rock.rotation[2])
    rockGeometry.translate(
      Math.cos(rock.angle) * rock.radius,
      rock.lift * 0.35,
      Math.sin(rock.angle) * rock.radius,
    )
    assignColors(rockGeometry, (_vertex, index) => {
      const palette = ['#210c09', '#3b1008', '#8c2108', '#170a08']
      return new THREE.Color(palette[(rockIndex + Math.floor(index / 3)) % palette.length]!)
    })
    geometries.push(rockGeometry)
  }

  const geometry = mergeGeometries(geometries, false)
  if (!geometry) throw new Error('Unable to merge meteor impact crater geometry')
  geometries.forEach((source) => source.dispose())
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxMeteorImpactGeometry'] = 'single-draw-grounded-molten-crater'
  geometry.userData['pfxMeteorImpactDrawCalls'] = 1
  geometry.userData['pfxMeteorImpactCraterFloor'] = true
  geometry.userData['pfxMeteorImpactEmbeddedCore'] = true
  geometry.userData['pfxMeteorImpactRimRockCount'] = rimRocks.length
  geometry.userData['pfxMeteorImpactRimRocksEmbedded'] = true
  geometry.userData['pfxMeteorImpactIrregularRim'] = true
  geometry.userData['pfxMeteorImpactBoundaryRing'] = 'continuous-asymmetric-outer-annulus'
  geometry.userData['pfxMeteorImpactBoundaryContinuous'] = true
  geometry.userData['pfxMeteorImpactBoundaryProfile'] = 'tapered-crater-ridge'
  geometry.userData['pfxMeteorImpactBoundaryMaximumWidth'] = 0.11
  geometry.userData['pfxMeteorImpactBoundaryOuterWall'] = false
  geometry.userData['pfxMeteorImpactBowlDepth'] = 0.11
  geometry.userData['pfxMeteorImpactBoundaryHeatNotchCount'] = boundaryHeatNotches.size
  geometry.userData['pfxMeteorImpactBoundaryInnerHeat'] = true
  geometry.userData['pfxMeteorImpactBoundaryOuterEdgeCool'] = true
  geometry.userData['pfxMeteorImpactBoundaryOuterRadius'] = 1.045
  geometry.userData['pfxMeteorImpactBoundaryHeight'] = 0.17
  geometry.userData['pfxMeteorImpactBoundaryWalls'] = true
  geometry.userData['pfxMeteorImpactCoreOffset'] = Math.hypot(...meteorOffset)
  geometry.userData['pfxMeteorImpactCoreRadius'] = meteorRadius
  geometry.userData['pfxMeteorImpactRimRockArchetypeCount'] = 3
  geometry.userData['pfxMeteorImpactUsesGemPrimitives'] = false
  geometry.userData['pfxMeteorImpactLipSegmentCount'] = lipSegmentCount
  geometry.userData['pfxMeteorImpactRadialHeatCrackCount'] = 8
  geometry.userData['pfxMeteorImpactCenterHeight'] = centerHeight
  geometry.userData['pfxMeteorImpactDepthSpan'] = geometry.boundingBox!.max.z - geometry.boundingBox!.min.z
  geometry.userData['pfxMeteorImpactHeightSpan'] = geometry.boundingBox!.max.y - geometry.boundingBox!.min.y
  return geometry
}

export function createPfxMeteorImpactMaterial(opacity: number): THREE.MeshStandardMaterial {
  const material = new THREE.MeshStandardMaterial({
    vertexColors: true,
    transparent: false,
    opacity: 1,
    blending: THREE.NormalBlending,
    depthWrite: true,
    side: THREE.FrontSide,
    toneMapped: false,
    metalness: 0.05,
    roughness: 0.64,
    emissive: new THREE.Color('#2d0702'),
    emissiveIntensity: 0.7,
  })
  material.userData['pfxMaterial'] = 'meteor-ring-molten-impact'
  material.userData['pfxAuthoredOpacity'] = opacity
  return material
}

export function applyPfxMeteorImpactAppearance(
  material: THREE.MeshStandardMaterial,
  heat: number,
): { visible: boolean; emissiveIntensity: number; colorMultiplier: number } {
  const energy = THREE.MathUtils.clamp(heat, 0, 1)
  const emissiveIntensity = 0.08 + Math.pow(energy, 0.75) * 0.62
  const colorMultiplier = 0.12 + Math.pow(energy, 1.2) * 0.88
  material.transparent = false
  material.opacity = 1
  material.emissiveIntensity = emissiveIntensity
  material.color.setRGB(
    colorMultiplier,
    colorMultiplier * (0.62 + energy * 0.38),
    colorMultiplier * (0.5 + energy * 0.5),
  )
  return { visible: energy > 0.02, emissiveIntensity, colorMultiplier }
}
export function getPfxMeteorImpactLightProfile(): {
  color: string
  intensity: number
  distance: number
  decay: number
} {
  return { color: '#ff5a16', intensity: 1.8, distance: 2.4, decay: 2 }
}

/** An open annulus prevents the generic filled shockwave disc from showing as
 * a bright wedge beneath low camera angles. It is deliberately wider on the
 * outside than the crater ridge so the expanding heat front remains legible. */
export function createPfxMeteorHeatFrontGeometry(): THREE.BufferGeometry {
  const innerRadius = 0.52
  const outerRadius = 0.78
  const geometry = new THREE.RingGeometry(innerRadius, outerRadius, 64, 1)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxMeteorHeatFrontGeometry'] = 'open-annular-pressure-front'
  geometry.userData['pfxMeteorHeatFrontCenterFilled'] = false
  geometry.userData['pfxMeteorHeatFrontInnerRadius'] = innerRadius
  geometry.userData['pfxMeteorHeatFrontOuterRadius'] = outerRadius
  return geometry
}

/** A faceted impact seed, broken pressure collar, and fourteen octahedral
 * shards form one merged draw. Per-vertex burst offsets collapse the cool
 * shards at onset, separate them by peak, and carry them outward in decay. */
export function createPfxShockwaveSpawnArrivalFlareGeometry(): THREE.BufferGeometry {
  const components: THREE.BufferGeometry[] = []
  const impactSeedRadius = 0.16
  const impactSeed = new THREE.OctahedronGeometry(impactSeedRadius, 0)
  impactSeed.scale(1.3, 0.45, 1)
  impactSeed.rotateY(0.32)
  impactSeed.translate(0, 0.078, 0)
  impactSeed.computeBoundingBox()
  const impactSeedPosition = impactSeed.getAttribute('position')
  const impactSeedEnergy = new Float32Array(impactSeedPosition.count)
  const impactSeedBurstOffset = new Float32Array(impactSeedPosition.count * 3)
  const impactSeedLayer = new Float32Array(impactSeedPosition.count).fill(0.45)
  const impactSeedMinY = impactSeed.boundingBox!.min.y
  const impactSeedHeight = Math.max(0.001, impactSeed.boundingBox!.max.y - impactSeedMinY)
  for (let index = 0; index < impactSeedPosition.count; index += 1) {
    const progress = THREE.MathUtils.clamp((impactSeedPosition.getY(index) - impactSeedMinY) / impactSeedHeight, 0, 1)
    impactSeedEnergy[index] = THREE.MathUtils.lerp(0.82, 1, progress)
  }
  impactSeed.setAttribute('aEnergy', new THREE.BufferAttribute(impactSeedEnergy, 1))
  impactSeed.setAttribute('aBurstOffset', new THREE.BufferAttribute(impactSeedBurstOffset, 3))
  impactSeed.setAttribute('aLayer', new THREE.BufferAttribute(impactSeedLayer, 1))
  components.push(impactSeed)
  const pressureCollarRadius = 0.39
  const pressureCollarTube = 0.065
  const collarSpecs = [
    { start: 0.03, arc: 0.42, lift: 0.13, tilt: 0.04, energy: 0.94 },
    { start: 0.64, arc: 0.46, lift: 0.112, tilt: -0.06, energy: 0.76 },
    { start: 1.28, arc: 0.4, lift: 0.136, tilt: 0.08, energy: 0.86 },
    { start: 1.9, arc: 0.44, lift: 0.118, tilt: -0.04, energy: 0.7 },
    { start: 2.54, arc: 0.41, lift: 0.13, tilt: 0.06, energy: 0.82 },
    { start: 3.18, arc: 0.45, lift: 0.116, tilt: -0.05, energy: 0.74 },
    { start: 3.82, arc: 0.39, lift: 0.134, tilt: 0.07, energy: 0.9 },
    { start: 4.44, arc: 0.43, lift: 0.114, tilt: -0.07, energy: 0.72 },
    { start: 5.08, arc: 0.4, lift: 0.128, tilt: 0.05, energy: 0.84 },
    { start: 5.7, arc: 0.44, lift: 0.12, tilt: -0.04, energy: 0.78 },
  ]
  collarSpecs.forEach((spec) => {
    const indexedCollar = new THREE.TorusGeometry(pressureCollarRadius, pressureCollarTube, 5, 16, spec.arc)
    const collar = indexedCollar.toNonIndexed()
    indexedCollar.dispose()
    collar.rotateZ(spec.start)
    collar.rotateX(-Math.PI / 2)
    collar.rotateZ(spec.tilt)
    collar.translate(0, spec.lift, 0)
    collar.computeBoundingBox()
    const position = collar.getAttribute('position')
    const energy = new Float32Array(position.count)
    const burstOffset = new Float32Array(position.count * 3)
    const layer = new Float32Array(position.count)
    const minY = collar.boundingBox!.min.y
    const height = Math.max(0.001, collar.boundingBox!.max.y - minY)
    for (let index = 0; index < position.count; index += 1) {
      const progress = THREE.MathUtils.clamp((position.getY(index) - minY) / height, 0, 1)
      energy[index] = THREE.MathUtils.lerp(spec.energy * 0.58, spec.energy, progress)
    }
    collar.setAttribute('aEnergy', new THREE.BufferAttribute(energy, 1))
    collar.setAttribute('aBurstOffset', new THREE.BufferAttribute(burstOffset, 3))
    collar.setAttribute('aLayer', new THREE.BufferAttribute(layer, 1))
    components.push(collar)
  })
  const fragmentSpecs = [
    { radius: 0.082, position: [-0.27, 0.13, 0.07] as const, scale: [1.65, 0.55, 0.5] as const, rotation: [0.2, -0.4, 0.32] as const, energy: 0.72 },
    { radius: 0.07, position: [0.2, 0.22, -0.09] as const, scale: [0.58, 1.75, 0.5] as const, rotation: [-0.3, 0.5, -0.28] as const, energy: 0.94 },
    { radius: 0.06, position: [0.07, 0.47, 0.1] as const, scale: [0.52, 1.9, 0.46] as const, rotation: [0.4, 0.1, 0.42] as const, energy: 1 },
    { radius: 0.074, position: [-0.13, 0.34, -0.18] as const, scale: [1.45, 0.58, 0.62] as const, rotation: [-0.1, -0.7, 0.52] as const, energy: 0.84 },
    { radius: 0.058, position: [0.3, 0.12, 0.16] as const, scale: [1.7, 0.5, 0.48] as const, rotation: [0.35, 0.8, -0.35] as const, energy: 0.68 },
    { radius: 0.064, position: [-0.31, 0.24, -0.1] as const, scale: [0.5, 1.72, 0.54] as const, rotation: [-0.25, 0.2, 0.6] as const, energy: 0.78 },
    { radius: 0.052, position: [0.02, 0.59, -0.04] as const, scale: [0.48, 1.9, 0.44] as const, rotation: [0.18, -0.3, -0.58] as const, energy: 0.9 },
    { radius: 0.056, position: [0.17, 0.39, 0.2] as const, scale: [1.5, 0.5, 0.56] as const, rotation: [-0.38, 0.65, 0.22] as const, energy: 0.82 },
    { radius: 0.05, position: [-0.08, 0.18, 0.23] as const, scale: [1.62, 0.48, 0.5] as const, rotation: [0.5, -0.2, -0.44] as const, energy: 0.76 },
    { radius: 0.047, position: [0.34, 0.27, -0.17] as const, scale: [1.48, 0.52, 0.48] as const, rotation: [-0.32, 0.42, 0.5] as const, energy: 0.8 },
    { radius: 0.045, position: [-0.35, 0.4, 0.13] as const, scale: [0.5, 1.55, 0.46] as const, rotation: [0.22, -0.54, -0.34] as const, energy: 0.88 },
    { radius: 0.043, position: [0.12, 0.63, 0.06] as const, scale: [0.48, 1.42, 0.5] as const, rotation: [-0.2, 0.76, 0.24] as const, energy: 0.96 },
    { radius: 0.046, position: [-0.21, 0.52, 0.23] as const, scale: [1.4, 0.48, 0.52] as const, rotation: [0.38, -0.64, 0.18] as const, energy: 0.84 },
    { radius: 0.044, position: [0.27, 0.48, -0.22] as const, scale: [0.46, 1.5, 0.48] as const, rotation: [-0.44, 0.28, -0.26] as const, energy: 0.9 },
  ]
  fragmentSpecs.forEach((spec) => {
    const fragment = new THREE.OctahedronGeometry(spec.radius, 0)
    const shardScale = spec.scale.map((axisScale) => Math.max(0.78, axisScale)) as [number, number, number]
    fragment.scale(shardScale[0], shardScale[1], shardScale[2])
    fragment.rotateX(spec.rotation[0])
    fragment.rotateY(spec.rotation[1])
    fragment.rotateZ(spec.rotation[2])
    fragment.translate(spec.position[0], spec.position[1], spec.position[2])
    fragment.computeBoundingBox()
    const position = fragment.getAttribute('position')
    const minY = fragment.boundingBox!.min.y
    const height = Math.max(0.001, fragment.boundingBox!.max.y - minY)
    const energy = new Float32Array(position.count)
    const burstOffset = new Float32Array(position.count * 3)
    const layer = new Float32Array(position.count).fill(1)
    for (let index = 0; index < position.count; index += 1) {
      const progress = THREE.MathUtils.clamp((position.getY(index) - minY) / height, 0, 1)
      energy[index] = THREE.MathUtils.lerp(spec.energy * 0.62, spec.energy, progress)
      burstOffset[index * 3] = spec.position[0]
      burstOffset[index * 3 + 1] = spec.position[1] - 0.1
      burstOffset[index * 3 + 2] = spec.position[2]
    }
    fragment.setAttribute('aEnergy', new THREE.BufferAttribute(energy, 1))
    fragment.setAttribute('aBurstOffset', new THREE.BufferAttribute(burstOffset, 3))
    fragment.setAttribute('aLayer', new THREE.BufferAttribute(layer, 1))
    components.push(fragment)
  })
  const geometry = mergeGeometries(components, false)
  components.forEach((component) => component.dispose())
  if (!geometry) throw new Error('Failed to merge shockwave spawn fragmented arrival geometry')
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxShockwaveSpawnGeometry'] = 'broken-pressure-collar-and-shards'
  geometry.userData['pfxShockwaveSpawnDrawCalls'] = 1
  geometry.userData['pfxShockwaveSpawnClosedVolume'] = true
  geometry.userData['pfxShockwaveSpawnComponentCount'] = fragmentSpecs.length + collarSpecs.length + 1
  geometry.userData['pfxShockwaveSpawnVerticalDominance'] = true
  geometry.userData['pfxShockwaveSpawnGroundProfile'] = false
  geometry.userData['pfxShockwaveSpawnAsymmetricLayout'] = true
  geometry.userData['pfxShockwaveSpawnFaceted'] = true
  geometry.userData['pfxShockwaveSpawnFragmented'] = true
  geometry.userData['pfxShockwaveSpawnAnimatedSeparation'] = true
  geometry.userData['pfxShockwaveSpawnVolumetricShards'] = true
  geometry.userData['pfxShockwaveSpawnMinShardMinorScale'] = 0.78
  geometry.userData['pfxShockwaveSpawnOutwardDecay'] = true
  geometry.userData['pfxShockwaveSpawnPressureCollar'] = true
  geometry.userData['pfxShockwaveSpawnPressureCollarArcCount'] = collarSpecs.length
  geometry.userData['pfxShockwaveSpawnPressureCollarOuterRadius'] = pressureCollarRadius + pressureCollarTube
  geometry.userData['pfxShockwaveSpawnImpactSeed'] = true
  geometry.userData['pfxShockwaveSpawnCoreRadius'] = impactSeedRadius
  geometry.userData['pfxShockwaveSpawnPlanarCards'] = false
  return geometry
}

export function createPfxShockwaveSpawnArrivalFlareMaterial(opacity: number): THREE.ShaderMaterial {
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uOpacity: { value: opacity },
      uTime: { value: 0 },
      uBurstProgress: { value: 0 },
      uInnerColor: { value: new THREE.Color('#ff6a1c') },
      uHotColor: { value: new THREE.Color('#fff3c4') },
      uRimColor: { value: new THREE.Color('#ff3d55') },
      uShardColor: { value: new THREE.Color('#b8ecff') },
    },
    vertexShader: `
      attribute float aEnergy;
      attribute vec3 aBurstOffset;
      attribute float aLayer;
      uniform float uBurstProgress;
      varying float vEnergy;
      varying vec3 vViewNormal;
      varying vec3 vViewPosition;
      varying vec3 vObjectPosition;
      varying float vLayer;
      void main() {
        float burstProgress = smoothstep(0.0, 1.0, min(uBurstProgress, 1.0));
        float outwardProgress = max(0.0, uBurstProgress - 1.0);
        vec3 animatedPosition = position
          - aBurstOffset * (1.0 - burstProgress)
          + aBurstOffset * outwardProgress * 0.82;
        vec4 viewPosition = modelViewMatrix * vec4(animatedPosition, 1.0);
        vEnergy = aEnergy;
        vViewNormal = normalize(normalMatrix * normal);
        vViewPosition = viewPosition.xyz;
        vObjectPosition = animatedPosition;
        vLayer = aLayer;
        gl_Position = projectionMatrix * viewPosition;
      }
    `,
    fragmentShader: `
      uniform float uOpacity;
      uniform vec3 uInnerColor;
      uniform vec3 uHotColor;
      uniform vec3 uRimColor;
      uniform vec3 uShardColor;
      varying float vEnergy;
      varying vec3 vViewNormal;
      varying vec3 vViewPosition;
      varying vec3 vObjectPosition;
      varying float vLayer;
      void main() {
        vec3 viewDirection = normalize(-vViewPosition);
        vec3 surfaceNormal = normalize(vViewNormal);
        float fresnel = pow(1.0 - abs(dot(surfaceNormal, viewDirection)), 1.55);
        float facetLight = 0.58 + 0.42 * max(0.0, dot(surfaceNormal, normalize(vec3(0.38, 0.72, 0.46))));
        float grain = 0.88 + 0.12 * sin(vObjectPosition.x * 31.0 + vObjectPosition.y * 43.0 + vObjectPosition.z * 37.0);
        float hotCore = 1.0 - abs(vEnergy * 2.0 - 1.0);
        vec3 body = mix(uInnerColor, uHotColor, clamp(hotCore * 0.86 + vEnergy * 0.18, 0.0, 1.0));
        vec3 groundedColor = mix(body * facetLight * grain, uRimColor, fresnel * 0.42);
        vec3 color = mix(groundedColor, uShardColor * (0.82 + facetLight * 0.28), vLayer * 0.72);
        float alpha = uOpacity * (0.52 + hotCore * 0.24 + fresnel * 0.22);
        gl_FragColor = vec4(color, alpha);
      }
    `,
    transparent: true,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    depthTest: true,
    side: THREE.DoubleSide,
    toneMapped: false,
  })
  material.userData['pfxMaterial'] = 'shockwave-spawn-arrival-flare'
  material.userData['pfxShockwaveSpawnArrivalFlare'] = true
  material.userData['pfxShockwaveSpawnPalette'] = 'gold-orange-pressure-energy'
  return material
}

export function createPfxShockwaveSpawnPressureFrontGeometry(): THREE.BufferGeometry {
  const innerRadius = 0.56
  const outerRadius = 0.78
  const radialSegments = 4
  const geometry = new THREE.RingGeometry(innerRadius, outerRadius, 64, radialSegments)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxShockwaveSpawnPressureFront'] = 'thick-open-annular-wave'
  geometry.userData['pfxShockwaveSpawnPressureFrontCenterFilled'] = false
  geometry.userData['pfxShockwaveSpawnPressureFrontInnerRadius'] = innerRadius
  geometry.userData['pfxShockwaveSpawnPressureFrontOuterRadius'] = outerRadius
  geometry.userData['pfxShockwaveSpawnPressureFrontBandWidth'] = outerRadius - innerRadius
  geometry.userData['pfxShockwaveSpawnPressureFrontRadialSegments'] = radialSegments
  return geometry
}

export function createPfxShockwaveSpawnPressureFrontMaterial(opacity: number): THREE.ShaderMaterial {
  const innerRadius = 0.56
  const outerRadius = 0.78
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uOpacity: { value: opacity },
      uInnerRadius: { value: innerRadius },
      uOuterRadius: { value: outerRadius },
      uInnerColor: { value: new THREE.Color('#ff8a32') },
      uCrestColor: { value: new THREE.Color('#ffe08a') },
      uAccentColor: { value: new THREE.Color('#ff3d6e') },
    },
    vertexShader: `
      varying float vRadius;
      varying float vAngle;
      void main() {
        vRadius = length(position.xy);
        vAngle = atan(position.y, position.x);
        gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
      }
    `,
    fragmentShader: `
      uniform float uOpacity;
      uniform float uInnerRadius;
      uniform float uOuterRadius;
      uniform vec3 uInnerColor;
      uniform vec3 uCrestColor;
      uniform vec3 uAccentColor;
      varying float vRadius;
      varying float vAngle;
      void main() {
        float bandWidth = uOuterRadius - uInnerRadius;
        float bandProgress = clamp((vRadius - uInnerRadius) / bandWidth, 0.0, 1.0);
        float innerFeather = smoothstep(0.0, 0.2, bandProgress);
        float outerFeather = 1.0 - smoothstep(0.76, 1.0, bandProgress);
        float crest = smoothstep(0.28, 0.62, bandProgress) * (1.0 - smoothstep(0.62, 0.84, bandProgress));
        float angularModulation = 0.72 + 0.28 * (0.5 + 0.5 * sin(vAngle * 9.0 + sin(vAngle * 3.0) * 1.7));
        float accentBand = pow(0.5 + 0.5 * sin(vAngle * 5.0 - bandProgress * 4.0), 4.0) * crest;
        float alpha = innerFeather * outerFeather * angularModulation * uOpacity;
        if (alpha < 0.004) discard;
        vec3 color = mix(mix(uInnerColor, uCrestColor, 0.28 + crest * 0.72), uAccentColor, accentBand * 0.82);
        gl_FragColor = vec4(color, alpha * (0.48 + crest * 0.52));
      }
    `,
    transparent: true,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    depthTest: true,
    side: THREE.DoubleSide,
    toneMapped: false,
  })
  material.userData['pfxMaterial'] = 'shockwave-spawn-pressure-front'
  material.userData['pfxShockwaveSpawnPressureFront'] = true
  return material
}

/** Closed irregular rock used by the meteor-only instanced chunk field. The
 * shared mesh keeps the layer to one draw while per-instance non-uniform
 * scale and full XYZ rotation prevent a repeated gem/billboard silhouette. */
export function createPfxMeteorChunkGeometry(): THREE.BufferGeometry {
  const raw = new THREE.IcosahedronGeometry(1, 3)
  raw.deleteAttribute('normal')
  raw.deleteAttribute('uv')
  const merged = mergeVertices(raw, 1e-4)
  raw.dispose()
  const position = merged.getAttribute('position')
  const point = new THREE.Vector3()
  for (let index = 0; index < position.count; index += 1) {
    point.fromBufferAttribute(position, index)
    const irregularity =
      0.82 +
      Math.sin(point.x * 7.1 + point.y * 3.7 - point.z * 5.3) * 0.11 +
      Math.sin(point.x * 2.9 - point.y * 6.2 + point.z * 4.1) * 0.07
    position.setXYZ(
      index,
      point.x * irregularity * 0.92,
      point.y * irregularity * 0.78,
      point.z * irregularity,
    )
  }
  position.needsUpdate = true
  merged.computeVertexNormals()
  merged.computeBoundingBox()
  merged.computeBoundingSphere()
  const colors = new Float32Array(position.count * 3)
  for (let index = 0; index < position.count; index += 1) {
    point.fromBufferAttribute(position, index)
    const strata = 0.5 + Math.sin(point.y * 15 + point.x * 3.4 - point.z * 2.7) * 0.5
    const fracture = Math.pow(1 - Math.abs(Math.sin(point.x * 8.3 + point.y * 5.7 + point.z * 6.1)), 10)
    const heat = THREE.MathUtils.clamp(fracture * 0.82 + strata * 0.12, 0, 1)
    colors[index * 3] = 0.3 + heat * 0.7
    colors[index * 3 + 1] = 0.2 + heat * 0.42
    colors[index * 3 + 2] = 0.14 + heat * 0.16
  }
  merged.setAttribute('color', new THREE.BufferAttribute(colors, 3))
  merged.userData['pfxMeteorChunkGeometry'] = 'irregular-closed-rock'
  merged.userData['pfxMeteorChunkDrawCalls'] = 1
  merged.userData['pfxMeteorChunkSurface'] = 'stratified-heat-fractured-rock'
  return merged
}

export function createPfxMeteorChunkMaterial(): THREE.MeshStandardMaterial {
  const material = new THREE.MeshStandardMaterial({
    color: '#ffffff',
    vertexColors: true,
    transparent: false,
    depthWrite: true,
    side: THREE.FrontSide,
    toneMapped: false,
    metalness: 0.03,
    roughness: 0.78,
    emissive: '#210704',
    emissiveIntensity: 0.16,
  })
  material.userData['pfxMaterial'] = 'meteor-instanced-rock-chunks'
  return material
}

export interface PfxMeteorChunkPose {
  visible: boolean
  incoming: boolean
  position: [number, number, number]
  rotation: [number, number, number]
  scale: [number, number, number]
  color: [number, number, number]
}

export function createPfxMeteorChunkLayout(
  emission: PfxParticleEmission,
  controls: PfxControls,
  elapsedSeconds: number,
): PfxMeteorChunkPose[] {
  const lifetime = Math.max(0.25, controls.lifetime)
  const timeScale = Math.max(0.05, controls.timing)
  const cycle = ((elapsedSeconds * timeScale) % (lifetime * PFX_BURST_CYCLE_MULTIPLIER)) /
    (lifetime * PFX_BURST_CYCLE_MULTIPLIER)
  const incomingCount = Math.max(2, Math.floor(emission.count * 0.28))
  const scale = controls.scale
  const gravity = (controls.gravity * 0.85 - 2.2) * scale
  const trajectoryEuler = new THREE.Euler().setFromQuaternion(
    new THREE.Quaternion().setFromUnitVectors(
      new THREE.Vector3(0, 0, 1),
      new THREE.Vector3(0.92, -1.1, 0.72).normalize(),
    ),
  )

  return Array.from({ length: emission.count }, (_, index): PfxMeteorChunkPose => {
    const incoming = index < incomingCount
    let x = 0
    let y = 0
    let z = 0
    let energy = 0
    if (incoming) {
      const trailProgress = index / Math.max(1, incomingCount - 1)
      const descent = THREE.MathUtils.clamp(cycle / 0.22, 0, 1)
      const headX = THREE.MathUtils.lerp(-0.92 * scale, 0, descent)
      const headY = THREE.MathUtils.lerp(1.18 * scale, 0.08 * scale, descent)
      const headZ = THREE.MathUtils.lerp(-0.72 * scale, 0, descent) + Math.sin(descent * Math.PI) * 0.12 * scale
      const trailDistance = (1 - trailProgress) * 0.38 * scale
      x = headX - 0.58 * trailDistance
      y = headY + 0.8 * trailDistance
      z = headZ - 1.1 * trailDistance
      const arrivalFade = 1 - THREE.MathUtils.clamp((cycle - 0.13) / 0.055, 0, 1)
      energy = Math.sin(Math.min(1, cycle / 0.035) * Math.PI / 2) * arrivalFade * (0.42 + trailProgress * 0.58)
    } else {
      const progress = THREE.MathUtils.clamp((cycle - 0.1) / 0.69, 0, 1)
      const live = cycle >= 0.1 && cycle < 0.55
      const travelAge = progress * 1.35
      const travel = emission.speed[index]! * travelAge
      x = emission.spawn[index * 3]! + emission.direction[index * 3]! * travel
      y = emission.spawn[index * 3 + 1]! + emission.direction[index * 3 + 1]! * travel + gravity * travelAge * travelAge * 0.5
        + Math.sin(Math.min(1, progress * 1.35) * Math.PI) * 0.14 * scale
      z = emission.spawn[index * 3 + 2]! + emission.direction[index * 3 + 2]! * travel
      y = Math.max(0.035 * scale, y)
      energy = live
        ? THREE.MathUtils.clamp(progress / 0.08, 0, 1) * Math.pow(Math.max(0, 1 - progress), 0.58)
        : 0
    }

    const size = emission.variance[index * 2]!
    const phase = emission.rotation[index * 2]! + elapsedSeconds * emission.rotation[index * 2 + 1]!
    const lead = incoming && index === incomingCount - 1
    const trailProgress = incoming ? index / Math.max(1, incomingCount - 1) : 0
    const base = incoming ? (lead ? 0.043 : 0.026 + trailProgress * 0.012) : 0.09
    const authoredSize = incoming && !lead ? Math.max(0.72, size) : size
    const scaleX = base * authoredSize * (incoming ? 1 : 0.78 + (index % 4) * 0.09)
    const scaleY = base * authoredSize * (incoming ? 0.72 : 0.62 + ((index * 3) % 5) * 0.12)
    const scaleZ = base * authoredSize * (lead ? 1.72 : incoming ? 3.2 - trailProgress * 0.4 : 0.8 + ((index * 5) % 4) * 0.11)
    const heat = THREE.MathUtils.clamp(energy * emission.variance[index * 2 + 1]!, 0, 1)
    return {
      visible: energy > 0.012,
      incoming,
      position: [x, y, z],
      rotation: incoming
        ? [trajectoryEuler.x, trajectoryEuler.y, trajectoryEuler.z]
        : [phase * (0.37 + (index % 3) * 0.11), phase * 0.71 + index * 0.83, phase * 1.07 + index * 0.41],
      scale: [scaleX, scaleY, scaleZ],
      color: [0.28 + heat * 0.54, 0.06 + heat * 0.32, 0.025 + heat * 0.155],
    }
  })
}

/** One-draw personal-shield shell with real missing panels. The primary
 * breach faces front-right while a smaller crown failure and branching cuts
 * break spherical symmetry from every review orbit. Removing triangles from
 * the mesh (rather than only masking pixels) gives the wound honest parallax,
 * silhouette change, and an open edge on mobile without another material. */
export function createPfxBarrierLowHealthGeometry(): THREE.BufferGeometry {
  const source = new THREE.SphereGeometry(0.72, 36, 24).toNonIndexed()
  const sourcePosition = source.getAttribute('position')
  const sourceNormal = source.getAttribute('normal')
  const sourceUv = source.getAttribute('uv')
  const positions: number[] = []
  const normals: number[] = []
  const uvs: number[] = []
  const mainBreach = new THREE.Vector3(0.78, 0.18, 0.6).normalize()
  const crownBreach = new THREE.Vector3(-0.54, 0.75, -0.38).normalize()
  const mainBreachThreshold = 0.92
  const crownBreachThreshold = 0.975
  const centroid = new THREE.Vector3()
  const vertex = new THREE.Vector3()
  const sourceTriangleCount = sourcePosition.count / 3
  let liftedPanelCount = 0
  let maximumPanelLift = 0

  for (let triangleIndex = 0; triangleIndex < sourceTriangleCount; triangleIndex += 1) {
    centroid.set(0, 0, 0)
    for (let corner = 0; corner < 3; corner += 1) {
      const index = triangleIndex * 3 + corner
      vertex.fromBufferAttribute(sourcePosition, index)
      centroid.add(vertex)
    }
    centroid.normalize()
    const mainFacing = centroid.dot(mainBreach)
    const crownFacing = centroid.dot(crownBreach)
    const azimuth = Math.atan2(centroid.z, centroid.x)
    const branchOne = Math.abs(centroid.y - (0.09 + Math.sin(azimuth * 2.4 + 0.5) * 0.11)) < 0.016
      && mainFacing > 0.46
    const branchTwo = Math.abs(centroid.y - (0.38 - Math.cos(azimuth * 1.7) * 0.1)) < 0.015
      && mainFacing > 0.55
    const removed = mainFacing > mainBreachThreshold || crownFacing > crownBreachThreshold || branchOne || branchTwo
    if (removed) continue

    // A few panels immediately behind the wound peel outward. Because the
    // sphere is non-indexed these are real detached triangular facets: they
    // catch profile light, interrupt the outer contour, and cast different
    // silhouettes from front/oblique/side without another draw call.
    const liftedPanel = mainFacing > 0.72
      && mainFacing <= mainBreachThreshold
      && Math.sin(azimuth * 6.2 + centroid.y * 8.4) > 0.54
      && triangleIndex % 4 === 0
    const panelLift = liftedPanel ? 0.18 + (mainBreachThreshold - mainFacing) * 0.5 : 0
    if (liftedPanel) {
      liftedPanelCount += 1
      maximumPanelLift = Math.max(maximumPanelLift, panelLift)
    }

    for (let corner = 0; corner < 3; corner += 1) {
      const index = triangleIndex * 3 + corner
      vertex.fromBufferAttribute(sourcePosition, index)
      if (liftedPanel) {
        vertex.addScaledVector(mainBreach, panelLift)
        vertex.addScaledVector(centroid, panelLift * 0.22)
      }
      positions.push(vertex.x, vertex.y, vertex.z)
      normals.push(sourceNormal.getX(index), sourceNormal.getY(index), sourceNormal.getZ(index))
      uvs.push(sourceUv.getX(index), sourceUv.getY(index))
    }
  }
  source.dispose()

  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  const retainedTriangleCount = positions.length / 9
  geometry.userData['pfxBarrierLowHealthGeometry'] = 'single-draw-open-asymmetric-fractured-shell'
  geometry.userData['pfxBarrierLowHealthDrawCalls'] = 1
  geometry.userData['pfxBarrierLowHealthOpenShell'] = true
  geometry.userData['pfxBarrierLowHealthBreachCount'] = 2
  geometry.userData['pfxBarrierLowHealthMainBreachThreshold'] = mainBreachThreshold
  geometry.userData['pfxBarrierLowHealthAsymmetric'] = true
  geometry.userData['pfxBarrierLowHealthLiftedPanelCount'] = liftedPanelCount
  geometry.userData['pfxBarrierLowHealthMaximumPanelLift'] = maximumPanelLift
  geometry.userData['pfxBarrierLowHealthRetainedTriangleRatio'] = retainedTriangleCount / sourceTriangleCount
  geometry.userData['pfxBarrierLowHealthDepthSpan'] = geometry.boundingBox!.max.z - geometry.boundingBox!.min.z
  geometry.userData['pfxBarrierLowHealthMainBreachDirection'] = mainBreach.toArray()
  return geometry
}

/** Four closed, faceted energy ribs escaping the primary shield wound. Their
 * deliberately separated trajectories replace a noisy sprite tangle with a
 * readable one-draw focal shape that survives axial and profile cameras. */
export function createPfxBarrierBreachRibGeometry(): THREE.BufferGeometry {
  const outward = new THREE.Vector3(0.78, 0.18, 0.6).normalize()
  const tangentA = new THREE.Vector3(0, 1, 0)
    .addScaledVector(outward, -outward.y)
    .normalize()
  const tangentB = new THREE.Vector3().crossVectors(outward, tangentA).normalize()
  const point = (distance: number, offsetA: number, offsetB: number): readonly [number, number, number] =>
    outward.clone().multiplyScalar(distance)
      .addScaledVector(tangentA, offsetA)
      .addScaledVector(tangentB, offsetB)
      .toArray() as [number, number, number]
  const ribSpecs = [
    { offsetA: 0.18, offsetB: 0.02, length: 0.42, bendA: 0.05, bendB: 0.04, width: 0.05 },
    { offsetA: -0.15, offsetB: 0.06, length: 0.31, bendA: -0.04, bendB: 0.08, width: 0.04 },
    { offsetA: 0.02, offsetB: 0.17, length: 0.5, bendA: 0.08, bendB: 0.03, width: 0.055 },
    { offsetA: 0.05, offsetB: -0.16, length: 0.36, bendA: -0.02, bendB: -0.07, width: 0.035 },
  ] as const
  const ribs = ribSpecs.map((spec) => ({
    root: point(0, spec.offsetA, spec.offsetB),
    mid: point(spec.length * 0.48, spec.offsetA + spec.bendA * 0.55, spec.offsetB + spec.bendB * 0.55),
    tip: point(spec.length, spec.offsetA + spec.bendA, spec.offsetB + spec.bendB),
    width: spec.width,
    length: spec.length,
  }))
  const positions: number[] = []
  const colors: number[] = []
  const rootColor: readonly [number, number, number] = [1, 0.08, 0.14]
  const middleColor: readonly [number, number, number] = [0.8, 0.03, 0.04]
  const tipColor: readonly [number, number, number] = [0.25, 0.01, 0.08]
  const facetSides = 7
  const tipWidthRatio = 0.28
  const pushTriangle = (
    a: THREE.Vector3,
    b: THREE.Vector3,
    c: THREE.Vector3,
    aColor: readonly [number, number, number],
    bColor: readonly [number, number, number],
    cColor: readonly [number, number, number],
  ) => {
    positions.push(a.x, a.y, a.z, b.x, b.y, b.z, c.x, c.y, c.z)
    colors.push(...aColor, ...bColor, ...cColor)
  }

  for (const [ribIndex, rib] of ribs.entries()) {
    const centers = [new THREE.Vector3(...rib.root), new THREE.Vector3(...rib.mid), new THREE.Vector3(...rib.tip)]
    const widths = [rib.width * 0.85, rib.width, rib.width * tipWidthRatio]
    const ringColors = [rootColor, middleColor, tipColor] as const
    const rings = centers.map((center, centerIndex) => {
      const previous = centers[Math.max(0, centerIndex - 1)]!
      const next = centers[Math.min(centers.length - 1, centerIndex + 1)]!
      const direction = next.clone().sub(previous).normalize()
      const reference = Math.abs(direction.y) > 0.86 ? new THREE.Vector3(0, 0, 1) : new THREE.Vector3(0, 1, 0)
      const tangent = new THREE.Vector3().crossVectors(direction, reference).normalize()
      const bitangent = new THREE.Vector3().crossVectors(direction, tangent).normalize()
      return Array.from({ length: facetSides }, (_, sideIndex) => {
        const angle = ribIndex * 0.31 + sideIndex / facetSides * Math.PI * 2
        return center.clone()
          .addScaledVector(tangent, Math.cos(angle) * widths[centerIndex]!)
          .addScaledVector(bitangent, Math.sin(angle) * widths[centerIndex]!)
      })
    })
    for (let ringIndex = 0; ringIndex < rings.length - 1; ringIndex += 1) {
      for (let sideIndex = 0; sideIndex < facetSides; sideIndex += 1) {
        const nextSide = (sideIndex + 1) % facetSides
        pushTriangle(rings[ringIndex]![sideIndex]!, rings[ringIndex + 1]![sideIndex]!, rings[ringIndex]![nextSide]!, ringColors[ringIndex]!, ringColors[ringIndex + 1]!, ringColors[ringIndex]!)
        pushTriangle(rings[ringIndex]![nextSide]!, rings[ringIndex + 1]![sideIndex]!, rings[ringIndex + 1]![nextSide]!, ringColors[ringIndex]!, ringColors[ringIndex + 1]!, ringColors[ringIndex + 1]!)
      }
    }
    for (let sideIndex = 0; sideIndex < facetSides; sideIndex += 1) {
      const nextSide = (sideIndex + 1) % facetSides
      pushTriangle(centers[0]!, rings[0]![nextSide]!, rings[0]![sideIndex]!, rootColor, rootColor, rootColor)
      pushTriangle(centers[2]!, rings[2]![sideIndex]!, rings[2]![nextSide]!, tipColor, tipColor, tipColor)
    }
  }
  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
  geometry.computeVertexNormals()
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxBarrierBreachGeometry'] = 'single-draw-closed-faceted-energy-ribs'
  geometry.userData['pfxBarrierBreachDrawCalls'] = 1
  geometry.userData['pfxBarrierBreachClosedFaces'] = true
  geometry.userData['pfxBarrierBreachRibCount'] = ribs.length
  geometry.userData['pfxBarrierBreachFacetSides'] = facetSides
  geometry.userData['pfxBarrierBreachTipWidthRatio'] = tipWidthRatio
  geometry.userData['pfxBarrierBreachCoreVertexCount'] = 0
  geometry.userData['pfxBarrierBreachInteriorStrutCount'] = 0
  geometry.userData['pfxBarrierBreachPalette'] = 'shield-crimson-strain-violet'
  geometry.userData['pfxBarrierBreachDepthSpan'] = geometry.boundingBox!.max.z - geometry.boundingBox!.min.z
  const rootYs = ribs.map((rib) => rib.root[1])
  geometry.userData['pfxBarrierBreachRootSpan'] = Math.max(...rootYs) - Math.min(...rootYs)
  geometry.userData['pfxBarrierBreachSharedRoot'] = false
  geometry.userData['pfxBarrierBreachOutwardAlignment'] = Math.min(...ribs.map((rib) =>
    new THREE.Vector3(...rib.tip).sub(new THREE.Vector3(...rib.root)).normalize().dot(outward),
  ))
  const ribLengths = ribs.map((rib) => rib.length)
  geometry.userData['pfxBarrierBreachLengthVariance'] = Math.max(...ribLengths) - Math.min(...ribLengths)
  return geometry
}

/** True-geometry target cage: a closed sphere plus front/back 3D corner-lock
 * brackets merged into one buffer. The brackets give onset an unmistakable
 * acquisition silhouette and remain honest prisms under camera orbit. */
export function createPfxTargetLockShellGeometry(): THREE.BufferGeometry {
  const sources: THREE.BufferGeometry[] = []
  const sphere = new THREE.SphereGeometry(0.72, 32, 24).toNonIndexed()
  sources.push(sphere)
  let bracketCount = 0
  for (const zSide of [-1, 1]) {
    for (const xSide of [-1, 1]) {
      for (const ySide of [-1, 1]) {
        const z = zSide * 0.66
        const horizontal = new THREE.BoxGeometry(0.24, 0.052, 0.07).toNonIndexed()
        horizontal.translate(xSide * 0.49, ySide * 0.6, z)
        sources.push(horizontal)
        const vertical = new THREE.BoxGeometry(0.052, 0.24, 0.07).toNonIndexed()
        vertical.translate(xSide * 0.6, ySide * 0.49, z)
        sources.push(vertical)
        bracketCount += 1
      }
    }
  }
  const positions: number[] = []
  const normals: number[] = []
  const uvs: number[] = []
  for (const source of sources) {
    const position = source.getAttribute('position')
    const normal = source.getAttribute('normal')
    const uv = source.getAttribute('uv')
    for (let index = 0; index < position.count; index += 1) {
      positions.push(position.getX(index), position.getY(index), position.getZ(index))
      normals.push(normal.getX(index), normal.getY(index), normal.getZ(index))
      uvs.push(uv.getX(index), uv.getY(index))
    }
    source.dispose()
  }
  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxTargetLockShellGeometry'] = 'single-draw-closed-sphere-with-3d-acquisition-brackets'
  geometry.userData['pfxTargetLockShellDrawCalls'] = 1
  geometry.userData['pfxTargetLockShellBracketCount'] = bracketCount
  geometry.userData['pfxTargetLockShellClosedGeometry'] = true
  return geometry
}

/** Detached closed honeycomb cells from the target's own shell. Unlike the
 * shared spear-like shield debris, these compact tangent plates keep the
 * hex-target identity after rupture and occupy distinct world-space octants.
 * Every cell is merged into one buffer so the authored read costs one draw. */
export function createPfxTargetBreakFragmentGeometry(): THREE.BufferGeometry {
  const positions: number[] = []
  const colors: number[] = []
  const faceColor: readonly [number, number, number] = [0.68, 0.95, 1]
  const edgeColor: readonly [number, number, number] = [0.14, 0.67, 0.94]
  const backColor: readonly [number, number, number] = [0.025, 0.24, 0.48]
  const cells = [
    { direction: [0.92, 0.22, 0.32], radius: 0.7, size: 0.115, sides: 6 },
    { direction: [-0.88, 0.4, -0.28], radius: 0.63, size: 0.105, sides: 6 },
    { direction: [0.18, 0.92, -0.42], radius: 0.66, size: 0.1, sides: 5 },
    { direction: [-0.32, -0.9, 0.5], radius: 0.72, size: 0.12, sides: 6 },
    { direction: [0.3, 0.12, 0.95], radius: 0.58, size: 0.095, sides: 6 },
    { direction: [-0.46, -0.16, -0.88], radius: 0.68, size: 0.11, sides: 5 },
    { direction: [0.58, -0.72, -0.4], radius: 0.61, size: 0.1, sides: 6 },
    { direction: [-0.64, 0.28, 0.72], radius: 0.56, size: 0.09, sides: 6 },
    { direction: [0.42, 0.68, 0.64], radius: 0.48, size: 0.085, sides: 5 },
    { direction: [-0.22, 0.62, -0.78], radius: 0.73, size: 0.105, sides: 6 },
    { direction: [0.72, -0.22, 0.66], radius: 0.52, size: 0.09, sides: 6 },
    { direction: [-0.76, -0.56, 0.34], radius: 0.47, size: 0.08, sides: 5 },
  ] as const
  const push = (point: THREE.Vector3, color: readonly [number, number, number]) => {
    positions.push(point.x, point.y, point.z)
    colors.push(...color)
  }
  const triangle = (
    a: THREE.Vector3,
    b: THREE.Vector3,
    c: THREE.Vector3,
    aColor: readonly [number, number, number],
    bColor: readonly [number, number, number],
    cColor: readonly [number, number, number],
  ) => {
    push(a, aColor)
    push(b, bColor)
    push(c, cColor)
  }
  const worldUp = new THREE.Vector3(0, 1, 0)
  const worldDepth = new THREE.Vector3(0, 0, 1)
  for (const [index, cell] of cells.entries()) {
    const normal = new THREE.Vector3(...cell.direction).normalize()
    const reference = Math.abs(normal.dot(worldUp)) > 0.82 ? worldDepth : worldUp
    const tangent = new THREE.Vector3().crossVectors(normal, reference).normalize()
    const bitangent = new THREE.Vector3().crossVectors(normal, tangent).normalize()
    const center = normal.clone().multiplyScalar(cell.radius)
    const thickness = 0.035 + (index % 3) * 0.009
    const frontCenter = center.clone().addScaledVector(normal, thickness)
    const backCenter = center.clone().addScaledVector(normal, -thickness)
    const phase = index * 0.61
    const front = Array.from({ length: cell.sides }, (_, side) => {
      const angle = phase + (side / cell.sides) * Math.PI * 2
      const radius = cell.size * (1 + 0.06 * Math.sin(index * 1.7 + side * 2.1))
      return frontCenter.clone()
        .addScaledVector(tangent, Math.cos(angle) * radius)
        .addScaledVector(bitangent, Math.sin(angle) * radius)
    })
    const back = front.map((point) => point.clone().addScaledVector(normal, -thickness * 2))
    for (let side = 0; side < cell.sides; side += 1) {
      const next = (side + 1) % cell.sides
      triangle(frontCenter, front[side]!, front[next]!, faceColor, faceColor, edgeColor)
      triangle(backCenter, back[next]!, back[side]!, backColor, edgeColor, backColor)
      triangle(front[side]!, back[side]!, back[next]!, edgeColor, backColor, backColor)
      triangle(front[side]!, back[next]!, front[next]!, edgeColor, backColor, edgeColor)
    }
  }
  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
  geometry.computeVertexNormals()
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxTargetBreakFragmentGeometry'] = 'single-draw-closed-honeycomb-shell-cells'
  geometry.userData['pfxTargetBreakFragmentDrawCalls'] = 1
  geometry.userData['pfxTargetBreakFragmentCount'] = cells.length
  geometry.userData['pfxTargetBreakClosedHoneycombCells'] = true
  geometry.userData['pfxTargetBreakDepthCrossingCount'] = cells.filter((cell) => Math.abs(new THREE.Vector3(...cell.direction).normalize().z) > 0.45).length
  geometry.userData['pfxTargetBreakMaximumRadius'] = geometry.boundingSphere!.radius
  return geometry
}

/** One-draw ground lock: a segmented annulus with four inward acquisition
 * brackets. It expands as the clear wave, so the same draw communicates both
 * "this target was selected" and "the target is now gone". */
export function createPfxTargetBreakReticleGeometry(
  color: THREE.ColorRepresentation = '#72d9ff',
): THREE.BufferGeometry {
  const positions: number[] = []
  const colors: number[] = []
  const base = new THREE.Color(color)
  const pale = base.clone().lerp(new THREE.Color('#ffffff'), 0.7)
  const shadow = base.clone().multiplyScalar(0.38)
  const push = (point: THREE.Vector3, value: THREE.Color) => {
    positions.push(point.x, point.y, point.z)
    colors.push(value.r, value.g, value.b)
  }
  const triangle = (a: THREE.Vector3, b: THREE.Vector3, c: THREE.Vector3, value: THREE.Color) => {
    push(a, value)
    push(b, value)
    push(c, value)
  }
  const quad = (a: THREE.Vector3, b: THREE.Vector3, c: THREE.Vector3, d: THREE.Vector3, value: THREE.Color) => {
    triangle(a, b, c, value)
    triangle(a, c, d, value)
  }
  const radialSegments = 48
  for (let segment = 0; segment < radialSegments; segment += 1) {
    // Four small gaps make the ring read as an acquisition reticle rather
    // than a decorative halo and leave visual room for the cardinal brackets.
    const cardinalPhase = segment % (radialSegments / 4)
    if (cardinalPhase <= 1 || cardinalPhase >= radialSegments / 4 - 1) continue
    const a0 = (segment / radialSegments) * Math.PI * 2
    const a1 = ((segment + 1) / radialSegments) * Math.PI * 2
    const inner = 0.67
    const outer = 0.72
    quad(
      new THREE.Vector3(Math.cos(a0) * inner, Math.sin(a0) * inner, 0),
      new THREE.Vector3(Math.cos(a0) * outer, Math.sin(a0) * outer, 0),
      new THREE.Vector3(Math.cos(a1) * outer, Math.sin(a1) * outer, 0),
      new THREE.Vector3(Math.cos(a1) * inner, Math.sin(a1) * inner, 0),
      segment % 3 === 0 ? pale : base,
    )
  }
  const bracketCount = 4
  for (let bracket = 0; bracket < bracketCount; bracket += 1) {
    const angle = bracket * Math.PI * 0.5
    const radial = new THREE.Vector3(Math.cos(angle), Math.sin(angle), 0)
    const tangent = new THREE.Vector3(-Math.sin(angle), Math.cos(angle), 0)
    const corner = radial.clone().multiplyScalar(0.82)
    const halfWidth = 0.17
    const thickness = 0.035
    const inner = corner.clone().addScaledVector(radial, -0.19)
    const outer = corner.clone().addScaledVector(radial, 0.02)
    quad(
      outer.clone().addScaledVector(tangent, -halfWidth),
      outer.clone().addScaledVector(tangent, -halfWidth + thickness),
      inner.clone().addScaledVector(tangent, -halfWidth + thickness),
      inner.clone().addScaledVector(tangent, -halfWidth),
      pale,
    )
    quad(
      inner.clone().addScaledVector(tangent, -halfWidth),
      inner.clone().addScaledVector(tangent, halfWidth),
      inner.clone().addScaledVector(radial, thickness).addScaledVector(tangent, halfWidth),
      inner.clone().addScaledVector(radial, thickness).addScaledVector(tangent, -halfWidth),
      base,
    )
    // Recessed registration tick gives the bracket a second value band.
    const tickCenter = radial.clone().multiplyScalar(0.91)
    quad(
      tickCenter.clone().addScaledVector(tangent, -0.055),
      tickCenter.clone().addScaledVector(tangent, 0.055),
      tickCenter.clone().addScaledVector(radial, 0.018).addScaledVector(tangent, 0.055),
      tickCenter.clone().addScaledVector(radial, 0.018).addScaledVector(tangent, -0.055),
      shadow,
    )
  }
  const cancellationBars = 2
  for (const diagonal of [-1, 1]) {
    const start = new THREE.Vector3(-0.34, diagonal * -0.34, 0)
    const end = new THREE.Vector3(0.34, diagonal * 0.34, 0)
    const direction = end.clone().sub(start).normalize()
    const normal = new THREE.Vector3(-direction.y, direction.x, 0).multiplyScalar(0.022)
    quad(
      start.clone().add(normal),
      end.clone().add(normal),
      end.clone().sub(normal),
      start.clone().sub(normal),
      pale,
    )
  }
  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxTargetBreakReticleGeometry'] = 'single-draw-segmented-lock-and-clear-wave'
  geometry.userData['pfxTargetBreakReticleDrawCalls'] = 1
  geometry.userData['pfxTargetBreakReticleBracketCount'] = bracketCount
  geometry.userData['pfxTargetBreakReticleRadialSegments'] = radialSegments
  geometry.userData['pfxTargetBreakReticleCancellationBars'] = cancellationBars
  return geometry
}

export function createPfxTargetBreakReticleMaterial(opacity: number): THREE.MeshBasicMaterial {
  const material = new THREE.MeshBasicMaterial({
    color: '#ffffff',
    vertexColors: true,
    transparent: true,
    opacity: THREE.MathUtils.clamp(opacity, 0, 1),
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    side: THREE.DoubleSide,
    toneMapped: false,
  })
  material.userData['pfxTargetBreakReticleMaterial'] = 'luminous-segmented-ground-lock'
  return material
}

/** Closed one-draw sci-fi exhaust outlet. The axial barrel, raised outlet
 * and rear collars, and four cooling fins are merged so the impact remains
 * mechanically attributable without spending a fourth draw. */
export function createPfxExhaustHitNozzleGeometry(): THREE.BufferGeometry {
  const sources: Array<{ geometry: THREE.BufferGeometry; color: THREE.Color }> = []
  const body = new THREE.CylinderGeometry(0.19, 0.24, 0.48, 12, 2, false).toNonIndexed()
  body.rotateZ(Math.PI / 2)
  body.translate(-0.2, 0, 0)
  sources.push({ geometry: body, color: new THREE.Color('#29445b') })
  const outlet = new THREE.TorusGeometry(0.24, 0.045, 8, 24).toNonIndexed()
  outlet.rotateY(Math.PI / 2)
  outlet.translate(0.045, 0, 0)
  sources.push({ geometry: outlet, color: new THREE.Color('#86d8ff') })
  const rear = new THREE.TorusGeometry(0.19, 0.026, 7, 20).toNonIndexed()
  rear.rotateY(Math.PI / 2)
  rear.translate(-0.43, 0, 0)
  sources.push({ geometry: rear, color: new THREE.Color('#477b9d') })
  const finCount = 4
  for (let fin = 0; fin < finCount; fin += 1) {
    const angle = (fin / finCount) * Math.PI * 2
    const geometry = new THREE.BoxGeometry(0.34, 0.055, 0.14).toNonIndexed()
    geometry.rotateX(angle)
    geometry.translate(-0.22, Math.cos(angle) * 0.235, Math.sin(angle) * 0.235)
    sources.push({ geometry, color: new THREE.Color(fin % 2 === 0 ? '#3d6e8f' : '#31546f') })
  }
  const positions: number[] = []
  const normals: number[] = []
  const uvs: number[] = []
  const colors: number[] = []
  for (const source of sources) {
    const position = source.geometry.getAttribute('position')
    const normal = source.geometry.getAttribute('normal')
    const uv = source.geometry.getAttribute('uv')
    for (let index = 0; index < position.count; index += 1) {
      positions.push(position.getX(index), position.getY(index), position.getZ(index))
      normals.push(normal.getX(index), normal.getY(index), normal.getZ(index))
      uvs.push(uv.getX(index), uv.getY(index))
      colors.push(source.color.r, source.color.g, source.color.b)
    }
    source.geometry.dispose()
  }
  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxExhaustHitNozzleGeometry'] = 'single-draw-closed-finned-axial-outlet'
  geometry.userData['pfxExhaustHitNozzleDrawCalls'] = 1
  geometry.userData['pfxExhaustHitNozzleClosedGeometry'] = true
  geometry.userData['pfxExhaustHitNozzleAxis'] = [1, 0, 0]
  geometry.userData['pfxExhaustHitNozzleFinCount'] = finCount
  return geometry
}

export function createPfxExhaustHitNozzleMaterial(opacity: number): THREE.MeshStandardMaterial {
  const material = new THREE.MeshStandardMaterial({
    color: '#ffffff',
    vertexColors: true,
    transparent: true,
    opacity: THREE.MathUtils.clamp(opacity, 0, 1),
    blending: THREE.NormalBlending,
    depthWrite: true,
    side: THREE.FrontSide,
    emissive: '#0a3b5e',
    emissiveIntensity: 0.18,
    roughness: 0.2,
    metalness: 0.72,
    flatShading: true,
    toneMapped: false,
  })
  material.userData['pfxExhaustHitNozzleMaterial'] = 'finned-blue-metal-with-hot-outlet-rim'
  return material
}

export function createPfxImpactCoreMaterial(
  opacity: number,
  color: THREE.ColorRepresentation,
): THREE.MeshStandardMaterial {
  const material = new THREE.MeshStandardMaterial({
    color,
    vertexColors: true,
    // Mesh flashes animate this value after construction, including from an
    // authored peak opacity of 1 down to zero during the same burst.
    transparent: true,
    opacity: Math.max(0, Math.min(1, opacity)),
    blending: THREE.NormalBlending,
    depthWrite: true,
    side: THREE.FrontSide,
    emissive: color,
    emissiveIntensity: 0.7,
    roughness: 0.44,
    metalness: 0.12,
    flatShading: true,
    toneMapped: false,
  })
  const shaderId = 'rim-specular-heat-seams-v1'
  const rimStrength = 0.24
  const heatSeamStrength = 0.12
  material.userData['pfxImpactCoreShader'] = shaderId
  material.userData['pfxImpactCoreRimStrength'] = rimStrength
  material.userData['pfxImpactCoreHeatSeamStrength'] = heatSeamStrength
  material.customProgramCacheKey = () => shaderId
  material.onBeforeCompile = (shader) => {
    shader.vertexShader = shader.vertexShader
      .replace(
        '#include <common>',
        '#include <common>\nvarying vec3 vPfxLocalPosition;\nvarying vec3 vPfxViewNormal;',
      )
      .replace(
        '#include <beginnormal_vertex>',
        '#include <beginnormal_vertex>\nvPfxLocalPosition = position;',
      )
      .replace(
        '#include <defaultnormal_vertex>',
        '#include <defaultnormal_vertex>\nvPfxViewNormal = normalize(transformedNormal);',
      )
    shader.fragmentShader = shader.fragmentShader
      .replace(
        '#include <common>',
        '#include <common>\nvarying vec3 vPfxLocalPosition;\nvarying vec3 vPfxViewNormal;',
      )
      .replace(
        '#include <opaque_fragment>',
        `
          vec3 pfxNormal = normalize(vPfxViewNormal);
          vec3 pfxView = normalize(vViewPosition);
          float pfxRim = pow(1.0 - clamp(abs(dot(pfxNormal, pfxView)), 0.0, 1.0), 2.4);
          float pfxSpecular = pow(max(dot(pfxNormal, normalize(vec3(0.32, 0.78, 0.54))), 0.0), 28.0);
          float pfxSeamWave = abs(sin(dot(vPfxLocalPosition, vec3(31.0, 19.0, 23.0)) + vPfxLocalPosition.x * 17.0));
          float pfxSeam = smoothstep(0.93, 0.995, pfxSeamWave);
          float pfxGrain = fract(sin(dot(floor(vPfxLocalPosition * 38.0), vec3(12.9898, 78.233, 37.719))) * 43758.5453);
          outgoingLight *= mix(0.97, 1.03, pfxGrain);
          outgoingLight += vec3(1.0, 0.34, 0.035) * pfxRim * ${rimStrength.toFixed(2)};
          outgoingLight += vec3(1.0, 0.93, 0.7) * pfxSpecular * 0.32;
          outgoingLight += vec3(1.0, 0.72, 0.22) * pfxSeam * ${heatSeamStrength.toFixed(2)};
          #include <opaque_fragment>
        `,
      )
  }
  return material
}

