export function createPfxGlyphTrailLifecycle(cycle: number): { progress: number; opacity: number; inscription: number; hold: number; erode: number; stage: 'write' | 'hold' | 'erode' } {
  const progress = THREE.MathUtils.clamp(cycle, 0, 1)
  if (progress < 0.12) { const inscription = roundMetric(progress / 0.12); return { progress, opacity: roundMetric(0.65 + inscription * 0.35), inscription, hold: 0, erode: 0, stage: 'write' } }
  if (progress <= 0.3) { const hold = roundMetric((progress - 0.12) / 0.18); return { progress, opacity: 1, inscription: 1, hold, erode: 0, stage: 'hold' } }
  const erode = roundMetric(THREE.MathUtils.clamp((progress - 0.3) / 0.38, 0, 1)); return { progress, opacity: roundMetric(Math.pow(1 - erode, 2)), inscription: 1, hold: 1, erode, stage: 'erode' }
}

export interface PfxGlyphTrailRuntimeState { cycle: number; periodSeconds: number; progress: number; opacity: number; inscription: number; hold: number; erode: number; stage: 'write' | 'hold' | 'erode' }
export function createPfxGlyphTrailRuntimeState(elapsedSeconds: number, timing: number, lifetime: number, tempo: number, motionMultiplier: number, target?: PfxGlyphTrailRuntimeState): PfxGlyphTrailRuntimeState {
  const rate = Math.max(.05, timing) * Math.max(.1, tempo) * Math.max(.1, motionMultiplier); const periodSeconds = 1.35 * Math.max(.25, lifetime); const cycle = roundMetric(THREE.MathUtils.clamp((Math.max(0, elapsedSeconds) * rate) / periodSeconds, 0, 1)); const lifecycle = createPfxGlyphTrailLifecycle(cycle)
  const state = target ?? { cycle: 0, periodSeconds: 0, progress: 0, opacity: 0, inscription: 0, hold: 0, erode: 0, stage: 'write' }; Object.assign(state, lifecycle, { cycle, periodSeconds }); return state
}

export function createPfxGlyphTrailStyleTreatment(styleEdgeHardness: number): { strokeTopology: 'rounded-calligraphic-strokes' | 'cut-arcane-strokes'; materialResponse: 'soft-ink-facets' | 'edge-lit-rune-facets'; writeCadence: 'staggered-handwriting' | 'synchronized-inscription'; erosionProfile: 'feathered-ink-cooling' | 'hard-script-dissolve' } {
  return styleEdgeHardness >= .65 ? { strokeTopology: 'cut-arcane-strokes', materialResponse: 'edge-lit-rune-facets', writeCadence: 'synchronized-inscription', erosionProfile: 'hard-script-dissolve' } : { strokeTopology: 'rounded-calligraphic-strokes', materialResponse: 'soft-ink-facets', writeCadence: 'staggered-handwriting', erosionProfile: 'feathered-ink-cooling' }
}

export function createPfxGlyphTrailMaterial(opacity: number, colorA: THREE.ColorRepresentation='#61e7ff', colorB: THREE.ColorRepresentation='#a78bfa', density=.55, styleEdgeHardness=.22): THREE.ShaderMaterial {
  const primary = new THREE.Color(colorA)
  const secondary = new THREE.Color(colorB)
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uOpacity: { value: THREE.MathUtils.clamp(opacity, 0, 1) },
      uCycle: { value: 0 },
      uColorA: { value: new THREE.Vector3(primary.r, primary.g, primary.b) },
      uColorB: { value: new THREE.Vector3(secondary.r, secondary.g, secondary.b) },
      uDensity: { value: THREE.MathUtils.clamp(density, .05, 1) },
      uStyleEdgeHardness: { value: THREE.MathUtils.clamp(styleEdgeHardness, 0, 1) },
    },
    vertexColors: true,
    transparent: false,
    blending: THREE.NormalBlending,
    depthWrite: true,
    side: THREE.FrontSide,
    toneMapped: false,
    vertexShader: /* glsl */ `
      varying vec3 vRuneColor;
      varying vec3 vRuneNormal;
      attribute float pfxRuneOrder;
      varying float vRuneOrder;
      void main() {
        vec4 viewPosition = modelViewMatrix * vec4(position, 1.0);
        vRuneColor = color;
        vRuneNormal = normalize(normalMatrix * normal);
        vRuneOrder = pfxRuneOrder;
        gl_Position = projectionMatrix * viewPosition;
      }
    `,
    fragmentShader: /* glsl */ `
      uniform float uOpacity;
      uniform float uCycle;
      uniform float uDensity;
      uniform float uStyleEdgeHardness;
      uniform vec3 uColorA;
      uniform vec3 uColorB;
      varying vec3 vRuneColor;
      varying vec3 vRuneNormal;
      varying float vRuneOrder;
      void main() {
        float hardStyle = step(.65, uStyleEdgeHardness);
        float staggeredHandwriting = smoothstep(.008 + vRuneOrder * .018, .048 + vRuneOrder * .018, uCycle);
        float synchronizedInscription = smoothstep(.015, .075, uCycle);
        float handwrittenReveal = mix(staggeredHandwriting, synchronizedInscription, hardStyle);
        float featheredInkCooling = 1.0 - smoothstep(.28 + (4.0 - vRuneOrder) * .055, .41 + (4.0 - vRuneOrder) * .055, uCycle);
        float hardScriptDissolve = 1.0 - smoothstep(.3 + (4.0 - vRuneOrder) * .045, .39 + (4.0 - vRuneOrder) * .045, uCycle);
        float oldestRuneErode = mix(featheredInkCooling, hardScriptDissolve, hardStyle);
        float densityReveal = smoothstep(.05, .38, uDensity);
        float densityMask = 1.0 - step(mix(1.5, 4.5, densityReveal), vRuneOrder);
        float earlyVisibility = uOpacity * handwrittenReveal * oldestRuneErode * densityMask;
        if (earlyVisibility < .08) discard;
        vec3 normal = normalize(vRuneNormal);
        vec3 keyLight = vec3(0.361, 0.822, 0.441);
        float facet = 0.82 + max(dot(normal, keyLight), 0.0) * 0.28;
        float rimLight = 1.0 - abs(normal.z);
        float runeGlow = 0.42 + rimLight * rimLight * .88;
        float softInkFacets = mix(.82, 1.04, facet);
        float edgeLitRuneFacets = max(.68 + facet * .28, rimLight * 1.18);
        float materialResponse = mix(softInkFacets, edgeLitRuneFacets, hardStyle);
        float palettePosition = clamp(vRuneOrder / 4.0, 0.0, 1.0);
        float inkAge = clamp((palettePosition - .08) / .7, 0.0, 1.0) * .9 + rimLight * .06;
        vec3 controlledInk = mix(uColorA, uColorB, inkAge);
        vec3 authoredFacet = mix(vec3(1.0), vRuneColor, .16);
        vec3 arcane = controlledInk * authoredFacet * materialResponse * (1.06 + runeGlow * .22);
        arcane += mix(uColorA, uColorB, .38) * rimLight * mix(.18, .5, hardStyle);
        gl_FragColor = vec4(arcane, 1.0);
      }
    `,
  })
  material.userData['pfxGlyphTrailMaterial'] = true
  material.userData['pfxGlyphTrailDrawCalls'] = 1
  material.userData['pfxGlyphTrailParticleCount'] = 0
  material.userData['pfxGlyphTrailFragmentTextureSamples'] = 0
  material.userData['pfxGlyphTrailFragmentNormalizeOps'] = 1
  material.userData['pfxGlyphTrailTransientAllocationsPerFrame'] = 0
  material.userData['pfxGlyphTrailMeshJustification'] = 'integrated-arcane-nib-with-sequential-closed-prism-handwriting-wake'
  return material
}

export function applyPfxGlyphTrailMaterialOpacity(material: THREE.ShaderMaterial, opacity: number): void {
  const uniform = material.uniforms['uOpacity']
  if (uniform) uniform.value = THREE.MathUtils.clamp(opacity, 0, 1)
}

export function applyPfxGlyphTrailMaterialCycle(material: THREE.ShaderMaterial, cycle: number): void {
  const uniform = material.uniforms['uCycle']
  if (uniform) uniform.value = THREE.MathUtils.clamp(cycle, 0, 1)
}

export function createPfxBeamTelegraphMaterial(
  opacity: number,
  geometryKind: 'lane' | 'aperture' = 'lane',
  primaryColor: THREE.ColorRepresentation = '#f04418',
  secondaryColor: THREE.ColorRepresentation = '#8eefff',
  density = 0.56,
  styleEdgeHardness = 0.54,
): THREE.ShaderMaterial {
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uOpacity: { value: THREE.MathUtils.clamp(opacity, 0, 1) },
      uCycle: { value: 0 },
      uAperture: { value: geometryKind === 'aperture' ? 1 : 0 },
      uPrimaryColor: { value: new THREE.Color(primaryColor) },
      uSecondaryColor: { value: new THREE.Color(secondaryColor) },
      uDensity: { value: THREE.MathUtils.clamp(density, 0.05, 1) },
      uStyleEdgeHardness: { value: THREE.MathUtils.clamp(styleEdgeHardness, 0, 1) },
    },
    vertexColors: true,
    transparent: true,
    blending: THREE.NormalBlending,
    depthWrite: false,
    side: THREE.FrontSide,
    toneMapped: false,
    vertexShader: /* glsl */ `
      varying vec3 vWarningColor;
      varying vec3 vWarningNormal;
      varying vec3 vWarningPosition;
      varying vec3 vViewPosition;
      void main() {
        vec4 viewPosition = modelViewMatrix * vec4(position, 1.0);
        vWarningColor = color;
        vWarningNormal = normalize(normalMatrix * normal);
        vWarningPosition = position;
        vViewPosition = viewPosition.xyz;
        gl_Position = projectionMatrix * viewPosition;
      }
    `,
    fragmentShader: /* glsl */ `
      uniform float uOpacity;
      uniform float uCycle;
      uniform float uAperture;
      uniform float uDensity;
      uniform float uStyleEdgeHardness;
      uniform vec3 uPrimaryColor;
      uniform vec3 uSecondaryColor;
      varying vec3 vWarningColor;
      varying vec3 vWarningNormal;
      varying vec3 vWarningPosition;
      varying vec3 vViewPosition;
      float warningHash(vec2 coordinate) {
        return fract(sin(dot(coordinate, vec2(127.1, 311.7))) * 43758.5453);
      }
      void main() {
        vec3 normal = normalize(vWarningNormal);
        vec3 viewDirection = normalize(-vViewPosition);
        float fresnel = pow(1.0 - abs(dot(normal, viewDirection)), 1.8);
        float lanePulse = 0.5 + 0.5 * sin(vWarningPosition.x * 6.2 - uCycle * 48.0);
        float countdown = smoothstep(0.02, 0.38, uCycle) * (1.0 - smoothstep(0.48, 0.58, uCycle));
        float energyNoise = warningHash(floor((vWarningPosition.xz + vec2(uCycle * 8.0, -uCycle * 3.0)) * 9.0));
        energyNoise = mix(energyNoise, 0.5 + 0.5 * sin(vWarningPosition.x * 13.0 + vWarningPosition.z * 17.0 - uCycle * 72.0), 0.55);
        float scanThreshold = mix(0.78, 0.62, uDensity);
        float scanSoftness = mix(0.12, 0.025, uStyleEdgeHardness);
        float scanRibbon = smoothstep(scanThreshold, scanThreshold + scanSoftness, lanePulse) * countdown;
        float charge = smoothstep(0.0, 0.3, uCycle);
        float revealHead = mix(-1.18, 1.94, charge);
        float fieldReveal = mix(1.0 - smoothstep(revealHead - 0.16, revealHead + 0.08, vWarningPosition.x), 1.0, uAperture);
        float dissolveNoise = smoothstep(0.48 + energyNoise * 0.08, 0.78, uCycle);
        float irisAngle = atan(vWarningPosition.z, vWarningPosition.y);
        float irisPulse = (0.5 + 0.5 * sin(irisAngle * 3.0 - uCycle * 38.0)) * uAperture;
        vec3 threatRed = uPrimaryColor;
        vec3 threatAmber = mix(uPrimaryColor, vec3(1.0, 0.62, 0.12), 0.42);
        vec3 warningWhite = mix(uPrimaryColor, vec3(1.0), 0.72);
        vec3 sourceCyan = uSecondaryColor;
        vec3 sourceWhite = mix(uSecondaryColor, vec3(1.0), 0.68);
        float current = 0.46 + countdown * 0.2 + energyNoise * 0.16 + scanRibbon * 0.26;
        vec3 controlledThreatColor = mix(vWarningColor, threatRed, 0.72);
        vec3 warning = controlledThreatColor * (0.52 + countdown * 0.3 + energyNoise * 0.12);
        warning += threatAmber * (fresnel * 0.32 + energyNoise * 0.16);
        warning += warningWhite * scanRibbon * 0.38;
        warning += warningWhite * irisPulse * 0.24;
        vec3 sourceEnergy = vWarningColor * (0.58 + energyNoise * 0.18)
          + sourceCyan * (0.24 + fresnel * 0.46)
          + sourceWhite * irisPulse * 0.34;
        warning = mix(warning, sourceEnergy, uAperture);
        float energyAlpha = clamp(current + fresnel * 0.18 + uAperture * 0.08 + irisPulse * 0.08, 0.0, 0.9);
        gl_FragColor = vec4(warning, uOpacity * fieldReveal * (1.0 - dissolveNoise) * energyAlpha);
      }
    `,
  })
  material.userData['pfxBeamTelegraphMaterial'] = 'directional-countdown-scan-with-fresnel-rails'
  material.userData['pfxBeamTelegraphEnergyTexture'] = 'procedural-scrolling-multiband-field'
  material.userData['pfxBeamTelegraphPalette'] = 'warm-threat-with-cool-source-accent'
  material.userData['pfxBeamTelegraphProjection'] = 'source-to-target-reveal-and-noise-dissolve'
  material.userData['pfxBeamTelegraphBloomDiscipline'] = 'crisp-alpha-field-with-additive-soft-current'
  material.userData['pfxBeamTelegraphControlBinding'] = 'primary-secondary-density-style'
  return material
}

export function applyPfxBeamTelegraphMaterialAppearance(material: THREE.ShaderMaterial, opacity: number, cycle: number): void {
  const opacityUniform = material.uniforms['uOpacity']
  if (opacityUniform) opacityUniform.value = THREE.MathUtils.clamp(opacity, 0, 1)
  const cycleUniform = material.uniforms['uCycle']
  if (cycleUniform) cycleUniform.value = THREE.MathUtils.clamp(cycle, 0, 1)
}

export function getPfxLaserSprayShotVisibility(cycle: number, sequence: number): number {
  const normalizedSequence = THREE.MathUtils.clamp(sequence, 0, 1)
  const shotStart = 0.005 + normalizedSequence * 0.22
  const shotAttack = THREE.MathUtils.smoothstep(cycle, shotStart, shotStart + 0.035)
  const shotRelease = 1 - THREE.MathUtils.smoothstep(cycle, 0.5, 0.66)
  const recoveryGhost = THREE.MathUtils.smoothstep(cycle, 0.6, 0.68)
    * (1 - THREE.MathUtils.smoothstep(cycle, 0.68, 0.8))
    * 0.28
  return roundMetric(Math.max(shotAttack * shotRelease, recoveryGhost))
}

export function createPfxLaserSprayMaterial(
  opacity: number,
  geometryKind: 'bolts' | 'nozzle' = 'bolts',
  primaryColor: THREE.ColorRepresentation = '#ff3d1f',
  secondaryColor: THREE.ColorRepresentation = '#ffb23c',
  density = 0.6,
  styleEdgeHardness = 0.54,
): THREE.ShaderMaterial {
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uOpacity: { value: THREE.MathUtils.clamp(opacity, 0, 1) },
      uCycle: { value: 0 },
      uNozzle: { value: geometryKind === 'nozzle' ? 1 : 0 },
      uPrimaryColor: { value: new THREE.Color(primaryColor) },
      uSecondaryColor: { value: new THREE.Color(secondaryColor) },
      uDensity: { value: THREE.MathUtils.clamp(density, 0.05, 1) },
      uStyleEdgeHardness: { value: THREE.MathUtils.clamp(styleEdgeHardness, 0, 1) },
    },
    vertexColors: true,
    transparent: true,
    blending: THREE.NormalBlending,
    depthWrite: false,
    side: THREE.FrontSide,
    toneMapped: false,
    vertexShader: /* glsl */ `
      uniform float uCycle;
      uniform float uNozzle;
      uniform float uDensity;
      uniform float uStyleEdgeHardness;
      uniform vec3 uPrimaryColor;
      uniform vec3 uSecondaryColor;
      attribute float spraySequence;
      attribute float sprayShell;
      varying vec3 vSprayColor;
      varying vec3 vSprayNormal;
      varying vec3 vSprayPosition;
      varying vec3 vViewPosition;
      varying float vSpraySequence;
      varying float vSprayShell;
      void main() {
        vec3 animatedPosition = position;
        float nozzleBreath = 1.0 + uNozzle * (
          0.035 + 0.075 * (0.5 + 0.5 * sin(uCycle * 44.0 + position.x * 8.0))
        );
        animatedPosition.yz *= nozzleBreath;
        float recoveryRetraction = 1.0 - (1.0 - uNozzle) * 0.62 * smoothstep(0.48, 0.76, uCycle);
        animatedPosition = mix(vec3(-1.4, 0.0, 0.0), animatedPosition, recoveryRetraction);
        vec4 viewPosition = modelViewMatrix * vec4(animatedPosition, 1.0);
        vSprayColor = color;
        vSprayNormal = normalize(normalMatrix * normal);
        vSprayPosition = animatedPosition;
        vViewPosition = viewPosition.xyz;
        vSpraySequence = spraySequence;
        vSprayShell = sprayShell;
        gl_Position = projectionMatrix * viewPosition;
      }
    `,
    fragmentShader: /* glsl */ `
      uniform float uOpacity;
      uniform float uCycle;
      uniform float uNozzle;
      uniform float uDensity;
      uniform float uStyleEdgeHardness;
      uniform vec3 uPrimaryColor;
      uniform vec3 uSecondaryColor;
      varying vec3 vSprayColor;
      varying vec3 vSprayNormal;
      varying vec3 vSprayPosition;
      varying vec3 vViewPosition;
      varying float vSpraySequence;
      varying float vSprayShell;
      void main() {
        vec3 normal = normalize(vSprayNormal);
        vec3 viewDirection = normalize(-vViewPosition);
        float fresnel = pow(1.0 - abs(dot(normal, viewDirection)), 1.7);
        float shotStart = 0.005 + vSpraySequence * 0.22;
        float shotAttack = smoothstep(shotStart, shotStart + 0.035, uCycle);
        float shotRelease = 1.0 - smoothstep(0.5, 0.66, uCycle);
        float recoveryGhost = smoothstep(0.6, 0.68, uCycle)
          * (1.0 - smoothstep(0.68, 0.8, uCycle))
          * 0.28;
        float salvoEnvelope = max(shotAttack * shotRelease, recoveryGhost);
        float nozzleEnvelope = smoothstep(0.0, 0.035, uCycle) * (1.0 - smoothstep(0.58, 0.8, uCycle));
        float axialScan = 0.5 + 0.5 * sin(vSprayPosition.x * 13.0 - uCycle * 86.0 + vSpraySequence * 11.0);
        float filamentThreshold = mix(0.82, 0.62, uDensity);
        float filamentBand = smoothstep(filamentThreshold, mix(0.99, 0.9, uStyleEdgeHardness), 0.5 + 0.5 * sin(vSprayPosition.x * 27.0 - uCycle * 118.0 + vSpraySequence * 17.0));
        float microPulse = 0.5 + 0.5 * sin(vSprayPosition.x * 51.0 + vSprayPosition.y * 23.0 - uCycle * 152.0);
        vec3 hotCore = mix(uSecondaryColor, vec3(1.0), 0.28);
        vec3 laserRed = uPrimaryColor;
        vec3 nozzleAmber = uSecondaryColor;
        vec3 nozzleWhite = mix(uSecondaryColor, vec3(1.0), 0.62);
        vec3 controlledLaserColor = mix(vSprayColor, laserRed, 0.72);
        vec3 boltEnergy = controlledLaserColor;
        boltEnergy += hotCore * (0.18 + axialScan * 0.24 + filamentBand * 0.3 + microPulse * 0.08 + fresnel * 0.2);
        float beamHalo = mix(0.0, 1.0, vSprayShell);
        float coreEdgeGradient = mix(0.72 + fresnel * 0.2, 0.1 + fresnel * 0.16, beamHalo);
        boltEnergy = mix(boltEnergy, hotCore + laserRed * 0.34, beamHalo * 0.42);
        vec3 nozzleEnergy = mix(vSprayColor, nozzleAmber, 0.42) + nozzleWhite * (fresnel * 0.42 + axialScan * 0.12);
        vec3 color = mix(boltEnergy, nozzleEnergy, uNozzle);
        float visibility = mix(salvoEnvelope, nozzleEnvelope, uNozzle);
        float terminalDissolve = 1.0 - 0.72 * smoothstep(1.36, 1.9, vSprayPosition.x);
        float edgeAlpha = 0.58 + fresnel * 0.22 + axialScan * 0.14;
        float alpha = uOpacity * visibility * edgeAlpha * coreEdgeGradient * mix(terminalDissolve, 1.0, uNozzle);
        if (alpha < 0.01) discard;
        gl_FragColor = vec4(color, clamp(alpha, 0.0, 0.92));
      }
    `,
  })
  material.userData['pfxLaserSprayMaterial'] = 'sequenced-world-space-salvo'
  material.userData['pfxLaserSprayShotCount'] = 5
  material.userData['pfxLaserSprayPeakStrandCount'] = 5
  material.userData['pfxLaserSprayBlendDiscipline'] = 'crisp-alpha-bolts-with-additive-endpoint-ricochets'
  material.userData['pfxLaserSprayPalette'] = 'unified-red-orange-amber-energy'
  material.userData['pfxLaserSprayUnifiedWarmPalette'] = true
  material.userData['pfxLaserSprayUniformRecovery'] = true
  material.userData['pfxLaserSprayIntegratedEndpointEnergyCount'] = 5
  material.userData['pfxLaserSprayParticleCount'] = 0
  material.userData['pfxLaserSprayControlBinding'] = 'primary-secondary-density-style'
  material.userData['pfxLaserSprayTemporalStructure'] = 'staggered-five-shot-attack-hold-release'
  return material
}

export function applyPfxLaserSprayMaterialAppearance(material: THREE.ShaderMaterial, opacity: number, cycle: number): void {
  const opacityUniform = material.uniforms['uOpacity']
  if (opacityUniform) opacityUniform.value = THREE.MathUtils.clamp(opacity, 0, 1)
  const cycleUniform = material.uniforms['uCycle']
  if (cycleUniform) cycleUniform.value = THREE.MathUtils.clamp(cycle, 0, 1)
}

export function createPfxGhostCriticalTalonMaterial(opacity: number): THREE.ShaderMaterial {
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uOpacity: { value: THREE.MathUtils.clamp(opacity, 0, 1) },
      uBodyColor: { value: new THREE.Color('#5d24a0') },
      uEdgeColor: { value: new THREE.Color('#bdf8ff') },
      uFresnelPower: { value: 2.35 },
    },
    vertexShader: /* glsl */ `
      attribute float pfxPart;
      varying vec3 vLocalPosition;
      varying vec3 vNormalView;
      varying vec3 vViewPosition;
      varying vec3 vVertexColor;
      varying float vPart;

      void main() {
        vec4 viewPosition = modelViewMatrix * vec4(position, 1.0);
        vLocalPosition = position;
        vNormalView = normalize(normalMatrix * normal);
        vViewPosition = -viewPosition.xyz;
        vVertexColor = color;
        vPart = pfxPart;
        gl_Position = projectionMatrix * viewPosition;
      }
    `,
    fragmentShader: /* glsl */ `
      uniform float uOpacity;
      uniform float uFresnelPower;
      uniform vec3 uBodyColor;
      uniform vec3 uEdgeColor;
      varying vec3 vLocalPosition;
      varying vec3 vNormalView;
      varying vec3 vViewPosition;
      varying vec3 vVertexColor;
      varying float vPart;

      void main() {
        vec3 normalDirection = normalize(vNormalView);
        vec3 viewDirection = normalize(vViewPosition);
        float fresnel = pow(clamp(1.0 - abs(dot(normalDirection, viewDirection)), 0.0, 1.0), uFresnelPower);
        float spectralVein = smoothstep(0.72, 0.98, sin(vLocalPosition.x * 19.0 + vLocalPosition.y * 13.0 - vLocalPosition.z * 9.0) * 0.5 + 0.5);
        float spectralFracture = smoothstep(0.8, 0.98, sin(vLocalPosition.x * 31.0 - vLocalPosition.y * 17.0 + vLocalPosition.z * 23.0) * 0.5 + 0.5);
        float tipEnergy = smoothstep(-0.28, 0.78, vLocalPosition.x);
        float valueSeparation = smoothstep(0.18, 0.82, vVertexColor.b + vVertexColor.g * 0.5);
        float skullMask = step(0.5, vPart);
        vec3 body = mix(vVertexColor, uBodyColor, 0.14 + (1.0 - valueSeparation) * 0.1);
        float facetLight = 0.38 + 0.62 * abs(dot(normalDirection, normalize(vec3(0.32, 0.78, 0.54))));
        float prismaticCrossSection = 0.68 + facetLight * 0.32;
        body *= prismaticCrossSection;
        vec3 talonColor = mix(body, uEdgeColor, clamp(fresnel * 0.82 + spectralVein * 0.22 + spectralFracture * 0.16 + tipEnergy * 0.12, 0.0, 0.94));
        float cleanSkullLight = 0.5 + 0.5 * max(0.0, dot(normalDirection, normalize(vec3(-0.35, 0.72, 0.6))));
        vec3 cleanSkullColor = mix(vVertexColor * (0.62 + cleanSkullLight * 0.38), uEdgeColor, fresnel * 0.48);
        vec3 spectralColor = mix(talonColor, cleanSkullColor, skullMask);
        float talonAlpha = uOpacity * clamp(0.42 + fresnel * 0.42 + spectralVein * 0.12 + spectralFracture * 0.08, 0.0, 0.96);
        float spectralAlpha = mix(talonAlpha, uOpacity * clamp(0.68 + fresnel * 0.26, 0.0, 0.96), skullMask);
        float darkVoidMarker = 1.0 - smoothstep(0.025, 0.11, max(vVertexColor.r, max(vVertexColor.g, vVertexColor.b)));
        float voidMarker = darkVoidMarker;
        float socketFalloff = 0.08 + fresnel * 0.22;
        vec3 socketColor = mix(vec3(0.003, 0.0, 0.012), vec3(0.11, 0.025, 0.19), socketFalloff);
        spectralColor = mix(spectralColor, socketColor, voidMarker);
        float voidAlpha = uOpacity * 0.9;
        spectralAlpha = mix(spectralAlpha, voidAlpha, voidMarker);
        gl_FragColor = vec4(spectralColor, spectralAlpha);
      }
    `,
    vertexColors: true,
    transparent: true,
    blending: THREE.NormalBlending,
    depthWrite: false,
    side: THREE.DoubleSide,
    toneMapped: false,
  })
  material.userData['pfxMaterial'] = 'violet-cyan-spectral-talon'
  return material
}

