export function createPfxTargetBreakFragmentMaterial(opacity: number): THREE.MeshStandardMaterial {
  const material = new THREE.MeshStandardMaterial({
    color: '#ffffff',
    vertexColors: true,
    transparent: true,
    opacity: THREE.MathUtils.clamp(opacity, 0, 1),
    blending: THREE.NormalBlending,
    depthWrite: true,
    side: THREE.DoubleSide,
    emissive: '#063c62',
    emissiveIntensity: 0.32,
    roughness: 0.18,
    metalness: 0.24,
    flatShading: true,
    toneMapped: false,
  })
  const shaderId = 'target-break-controlled-crystal-rim-v1'
  material.userData['pfxTargetBreakFragmentMaterial'] = 'faceted-cyan-crystal-with-controlled-rim'
  material.customProgramCacheKey = () => shaderId
  material.onBeforeCompile = (shader) => {
    shader.vertexShader = shader.vertexShader
      .replace('#include <common>', '#include <common>\nvarying vec3 vPfxTargetViewNormal;\nvarying vec3 vPfxTargetLocalPosition;')
      .replace('#include <beginnormal_vertex>', '#include <beginnormal_vertex>\nvPfxTargetLocalPosition = position;')
      .replace('#include <defaultnormal_vertex>', '#include <defaultnormal_vertex>\nvPfxTargetViewNormal = normalize(transformedNormal);')
    shader.fragmentShader = shader.fragmentShader
      .replace('#include <common>', '#include <common>\nvarying vec3 vPfxTargetViewNormal;\nvarying vec3 vPfxTargetLocalPosition;')
      .replace('#include <opaque_fragment>', `
        vec3 pfxTargetNormal = normalize(vPfxTargetViewNormal);
        vec3 pfxTargetView = normalize(vViewPosition);
        float pfxTargetRim = pow(1.0 - clamp(abs(dot(pfxTargetNormal, pfxTargetView)), 0.0, 1.0), 2.2);
        float pfxTargetFacet = pow(max(dot(pfxTargetNormal, normalize(vec3(0.28, 0.82, 0.5))), 0.0), 18.0);
        float pfxTargetBand = 0.5 + 0.5 * sin(dot(vPfxTargetLocalPosition, vec3(17.0, 23.0, 13.0)));
        outgoingLight *= mix(0.86, 1.08, pfxTargetBand);
        outgoingLight += vec3(0.08, 0.58, 0.92) * pfxTargetRim * 0.28;
        outgoingLight += vec3(0.82, 0.97, 1.0) * pfxTargetFacet * 0.24;
        #include <opaque_fragment>
      `)
  }
  return material
}

export function createPfxMuzzleFlameGeometry(radialSegments = 8): THREE.BufferGeometry {
  const segments = Math.max(6, Math.floor(radialSegments))
  const positions: number[] = []
  const uvs: number[] = []
  const colors: number[] = []
  type MuzzleAxialRing = {
    x: number
    radius: number
    offset: readonly [number, number]
    uProgress: number
    color: readonly [number, number, number]
  }
  const rings: ReadonlyArray<MuzzleAxialRing> = [
    { x: -0.1, radius: 0.2, offset: [-0.015, 0.025], uProgress: 0, color: [1, 1, 0.9] },
    { x: 0.08, radius: 0.26, offset: [0.025, 0.055], uProgress: 0.28, color: [1, 0.9, 0.55] },
    { x: 0.27, radius: 0.19, offset: [0.075, -0.04], uProgress: 0.58, color: [1, 0.7, 0.25] },
    { x: 0.44, radius: 0.11, offset: [0.1, -0.075], uProgress: 0.82, color: [1, 0.5, 0.08] },
  ]
  const tip: readonly [number, number, number] = [0.58, 0.1, -0.08]
  const tipColor: readonly [number, number, number] = [1, 0.4, 0.05]
  const innerRings: ReadonlyArray<MuzzleAxialRing> = [
    { x: -0.04, radius: 0.09, offset: [-0.01, 0.01], uProgress: 0.08, color: [1, 1, 0.96] },
    { x: 0.14, radius: 0.12, offset: [-0.025, 0.035], uProgress: 0.4, color: [1, 0.96, 0.7] },
    { x: 0.3, radius: 0.065, offset: [-0.035, 0.055], uProgress: 0.7, color: [1, 0.78, 0.3] },
  ]
  const innerTip: readonly [number, number, number] = [0.44, -0.04, 0.06]
  const innerTipColor: readonly [number, number, number] = [1, 0.62, 0.12]
  const directionalSlice = PFX_MUZZLE_FLASH_ATLAS.slices['directional-1']
  const insetU = directionalSlice.w * 0.04
  const insetV = directionalSlice.h * 0.04
  const u0 = directionalSlice.u + insetU
  const uSpan = directionalSlice.w - insetU * 2
  const vCenter = directionalSlice.v + directionalSlice.h * 0.5
  const vRadius = directionalSlice.h * 0.46
  const pushVertex = (position: readonly [number, number, number], uv: readonly [number, number], color: readonly [number, number, number]) => {
    positions.push(...position)
    uvs.push(...uv)
    colors.push(...color)
  }
  const pushTriangle = (
    a: readonly [number, number, number], aUv: readonly [number, number], aColor: readonly [number, number, number],
    b: readonly [number, number, number], bUv: readonly [number, number], bColor: readonly [number, number, number],
    c: readonly [number, number, number], cUv: readonly [number, number], cColor: readonly [number, number, number],
  ) => {
    pushVertex(a, aUv, aColor)
    pushVertex(b, bUv, bColor)
    pushVertex(c, cUv, cColor)
  }
  const appendTaperedShell = (
    shellRings: ReadonlyArray<MuzzleAxialRing>,
    shellTip: readonly [number, number, number],
    shellTipColor: readonly [number, number, number],
    uvRadiusScale: number,
  ) => {
    const ringVertices = shellRings.map((ring, ringIndex) => Array.from({ length: segments }, (_, segment) => {
      const angle = (segment / segments) * Math.PI * 2
      const irregularity = 1 + 0.07 * Math.sin(angle * 3 + ringIndex * 1.7) + 0.035 * Math.sin(angle * 5 + 0.8)
      const radius = ring.radius * irregularity
      return {
        position: [
          ring.x,
          ring.offset[0] + Math.cos(angle) * radius,
          ring.offset[1] + Math.sin(angle) * radius,
        ] as const,
        uv: [u0 + uSpan * ring.uProgress, vCenter + Math.cos(angle) * vRadius * uvRadiusScale] as const,
        color: ring.color,
      }
    }))
    for (let ringIndex = 0; ringIndex < ringVertices.length - 1; ringIndex += 1) {
      const current = ringVertices[ringIndex]!
      const next = ringVertices[ringIndex + 1]!
      for (let segment = 0; segment < segments; segment += 1) {
        const following = (segment + 1) % segments
        pushTriangle(
          current[segment]!.position, current[segment]!.uv, current[segment]!.color,
          next[following]!.position, next[following]!.uv, next[following]!.color,
          next[segment]!.position, next[segment]!.uv, next[segment]!.color,
        )
        pushTriangle(
          current[segment]!.position, current[segment]!.uv, current[segment]!.color,
          current[following]!.position, current[following]!.uv, current[following]!.color,
          next[following]!.position, next[following]!.uv, next[following]!.color,
        )
      }
    }
    const finalRing = ringVertices.at(-1)!
    const tipUv: readonly [number, number] = [u0 + uSpan, vCenter]
    for (let segment = 0; segment < segments; segment += 1) {
      const following = (segment + 1) % segments
      pushTriangle(
        finalRing[segment]!.position, finalRing[segment]!.uv, finalRing[segment]!.color,
        finalRing[following]!.position, finalRing[following]!.uv, finalRing[following]!.color,
        shellTip, tipUv, shellTipColor,
      )
    }
  }
  appendTaperedShell(rings, tip, tipColor, 1)
  appendTaperedShell(innerRings, innerTip, innerTipColor, 0.46)

  // The axial camera sees the open end of the directional shell. A softly
  // irregular ignition bloom closes it without exposing an atlas-star icon.
  // It shares this BufferGeometry/material, preserving one draw call.
  const capSlice = PFX_MUZZLE_FLASH_ATLAS.slices['radial-1']
  const capCenter: readonly [number, number, number] = [0.03, 0.012, -0.014]
  const capRadius = 0.16
  const capAspect: readonly [number, number] = [1.08, 0.86]
  const capSegments = 16
  const capUvRadius = 0.18
  const capUvCenter: readonly [number, number] = [capSlice.u + capSlice.w * 0.5, capSlice.v + capSlice.h * 0.5]
  const capColor: readonly [number, number, number] = [1, 1, 0.86]
  const capRingColor: readonly [number, number, number] = [1, 0.46, 0.04]
  const capPosition = (angle: number): readonly [number, number, number] => {
    const radialAsymmetry = 1 + 0.04 * Math.sin(angle + 0.35) + 0.025 * Math.sin(angle * 3 - 0.4)
    const depthAsymmetry = 1 + 0.03 * Math.cos(angle - 0.7)
    return [
      capCenter[0],
      capCenter[1] + Math.cos(angle) * capRadius * capAspect[0] * radialAsymmetry,
      capCenter[2] + Math.sin(angle) * capRadius * capAspect[1] * depthAsymmetry,
    ]
  }
  for (let segment = 0; segment < capSegments; segment += 1) {
    const a0 = (segment / capSegments) * Math.PI * 2
    const a1 = ((segment + 1) / capSegments) * Math.PI * 2
    const ring0 = capPosition(a0)
    const ring1 = capPosition(a1)
    const uv0: readonly [number, number] = [capUvCenter[0] + Math.cos(a0) * capSlice.w * capUvRadius, capUvCenter[1] + Math.sin(a0) * capSlice.h * capUvRadius]
    const uv1: readonly [number, number] = [capUvCenter[0] + Math.cos(a1) * capSlice.w * capUvRadius, capUvCenter[1] + Math.sin(a1) * capSlice.h * capUvRadius]
    pushTriangle(capCenter, capUvCenter, capColor, ring0, uv0, capRingColor, ring1, uv1, capRingColor)
  }
  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.computeVertexNormals()
  geometry.computeBoundingSphere()
  geometry.userData['pfxMuzzleGeometry'] = 'connected-tapered-volume-with-radial-cap'
  geometry.userData['pfxMuzzleLayers'] = ['nested-hot-core', 'connected-flame-body', 'radial-front-cap']
  geometry.userData['pfxMuzzleLobeCount'] = 2
  geometry.userData['pfxMuzzleAxialRingCount'] = rings.length
  geometry.userData['pfxMuzzleInnerAxialRingCount'] = innerRings.length
  geometry.userData['pfxMuzzleAtlasSlices'] = ['directional-1', 'radial-1']
  geometry.userData['pfxMuzzleBodyProfile'] = 'short-layered-percussive-shell'
  geometry.userData['pfxMuzzleBodyTip'] = [...tip]
  geometry.userData['pfxMuzzleBodyMaxRadius'] = Math.max(...rings.map((ring) => ring.radius))
  geometry.userData['pfxMuzzleInnerTip'] = [...innerTip]
  geometry.userData['pfxMuzzleRadialCapUvRadius'] = capUvRadius
  geometry.userData['pfxMuzzleRadialCapRadius'] = capRadius
  geometry.userData['pfxMuzzleRadialCapProfile'] = 'offset-soft-ignition-bloom'
  geometry.userData['pfxMuzzleRadialCapCenter'] = [...capCenter]
  geometry.userData['pfxMuzzleRadialCapAspect'] = [...capAspect]
  geometry.userData['pfxMuzzleRadialCapSegments'] = capSegments
  return geometry
}

/** The connected flame body is a closed shell. Drawing its back faces would
 * reveal the transparent interior as a split U-shape on the barrel axis. */
export function createPfxMuzzleFlameMaterial(opacity: number): THREE.MeshBasicMaterial {
  const material = new THREE.MeshBasicMaterial({
    map: getPfxMuzzleFlashAtlasTexture(),
    vertexColors: true,
    transparent: true,
    opacity: opacity * 0.92,
    blending: THREE.NormalBlending,
    depthWrite: false,
    alphaTest: 0.01,
    side: THREE.FrontSide,
  })
  const axisWorld = new THREE.Vector3(1, 0, 0)
  const axisView = new THREE.Vector3(1, 0, 0)
  const worldQuaternion = new THREE.Quaternion()
  material.userData['pfxMuzzleAxialFade'] = 'directional-atlas-only@0.82-0.96'
  material.userData['pfxMuzzleHeatRamp'] = 'tight-yellow-core-to-saturated-orange-edge'
  material.customProgramCacheKey = () => 'pfx-muzzle-axial-fade-heat-ramp-v3'
  material.onBeforeCompile = (shader) => {
    shader.uniforms['uPfxAxisView'] = { value: axisView }
    shader.vertexShader = shader.vertexShader
      .replace(
        '#include <common>',
        '#include <common>\nvarying vec3 vPfxViewPosition;',
      )
      .replace(
        '#include <project_vertex>',
        '#include <project_vertex>\nvPfxViewPosition = mvPosition.xyz;',
      )
    shader.fragmentShader = shader.fragmentShader
      .replace(
        '#include <common>',
        '#include <common>\nuniform vec3 uPfxAxisView;\nvarying vec3 vPfxViewPosition;',
      )
      .replace(
        '#include <map_fragment>',
        `#include <map_fragment>
float pfxAtlasEnergy = max(diffuseColor.g, diffuseColor.b);
float pfxHeatCore = smoothstep(0.82, 0.99, pfxAtlasEnergy);
vec3 pfxHeatRamp = mix(vec3(1.0, 0.06, 0.0), vec3(1.0, 0.55, 0.05), pfxHeatCore);
diffuseColor.rgb = pfxHeatRamp * mix(0.62, 1.08, pfxAtlasEnergy);
float pfxRadialCapWeight = 1.0 - step(0.5, vMapUv.y);
vec2 pfxRadialCapUv = (vMapUv - vec2(0.125, 0.25)) / vec2(0.25, 0.5);
float pfxRadialAngle = atan(pfxRadialCapUv.y, pfxRadialCapUv.x);
float pfxRadialRadius = length(pfxRadialCapUv);
float pfxRadialEdge = 0.145 + 0.018 * sin(pfxRadialAngle * 3.0 + 0.6) + 0.012 * sin(pfxRadialAngle * 5.0 - 0.4);
float pfxRadialCapAlpha = 1.0 - smoothstep(pfxRadialEdge - 0.045, pfxRadialEdge, pfxRadialRadius);
diffuseColor.a *= mix(1.0, pfxRadialCapAlpha, pfxRadialCapWeight);
float pfxDirectionalAtlasWeight = step(0.5, vMapUv.y);
float pfxAxialAlignment = abs(dot(normalize(-vPfxViewPosition), normalize(uPfxAxisView)));
float pfxDirectionalVisibility = 1.0 - smoothstep(0.82, 0.96, pfxAxialAlignment);
diffuseColor.a *= mix(1.0, pfxDirectionalVisibility, pfxDirectionalAtlasWeight);`,
      )
    material.userData['pfxMuzzleShader'] = shader
  }
  material.onBeforeRender = (_renderer, _scene, camera, _geometry, object) => {
    object.getWorldQuaternion(worldQuaternion)
    axisWorld.set(1, 0, 0).applyQuaternion(worldQuaternion)
    axisView.copy(axisWorld).transformDirection(camera.matrixWorldInverse)
    const shader = material.userData['pfxMuzzleShader'] as { uniforms?: Record<string, { value: unknown }> } | undefined
    const uniform = shader?.uniforms?.['uPfxAxisView']
    if (uniform) uniform.value = axisView
  }
  return material
}

export function createPfxHealingGlyphMaterial(opacity: number, color: THREE.ColorRepresentation): THREE.MeshStandardMaterial {
  const material = new THREE.MeshStandardMaterial({
    color,
    emissive: color,
    emissiveIntensity: 0.55,
    roughness: 0.38,
    metalness: 0,
    transparent: true,
    opacity: Math.max(0, Math.min(1, opacity)),
    blending: THREE.NormalBlending,
    depthWrite: false,
    side: THREE.DoubleSide,
    toneMapped: true,
  })
  material.userData['pfxHealingGlyph'] = 'restoration-leaf-bloom'
  material.userData['pfxHealingGlyphGeometry'] = 'beveled-life-leaf'
  return material
}

export function createPfxHealingVineMaterial(opacity: number, color: THREE.ColorRepresentation): THREE.MeshStandardMaterial {
  const vineColor = new THREE.Color(color)
  const hsl = { h: 0, s: 0, l: 0 }
  vineColor.getHSL(hsl)
  vineColor.setHSL(hsl.h, Math.max(0.72, hsl.s), Math.min(0.42, hsl.l * 0.72))
  const material = new THREE.MeshStandardMaterial({
    color: vineColor,
    emissive: vineColor,
    emissiveIntensity: 0.38,
    roughness: 0.34,
    metalness: 0,
    transparent: true,
    opacity: Math.max(0, Math.min(1, opacity)) * 0.9,
    blending: THREE.NormalBlending,
    depthWrite: false,
    side: THREE.DoubleSide,
    toneMapped: true,
  })
  material.userData['pfxHealingVolume'] = 'single-life-vine'
  return material
}

export function createPfxHealingLeafEdgeMaterial(opacity: number, color: THREE.ColorRepresentation): THREE.MeshStandardMaterial {
  const edgeColor = new THREE.Color(color).multiplyScalar(0.42)
  const material = new THREE.MeshStandardMaterial({
    color: edgeColor,
    emissive: edgeColor,
    emissiveIntensity: 0.24,
    roughness: 0.46,
    metalness: 0,
    transparent: true,
    opacity: Math.max(0, Math.min(1, opacity)),
    blending: THREE.NormalBlending,
    depthWrite: false,
    side: THREE.DoubleSide,
    toneMapped: true,
  })
  material.userData['pfxHealingLeafLayer'] = 'extruded-edge'
  return material
}

export function createPfxHealingFocalMaterial(opacity: number): THREE.MeshStandardMaterial {
  const material = new THREE.MeshStandardMaterial({
    color: '#68ffc0',
    emissive: '#37d98a',
    emissiveIntensity: 0.82,
    roughness: 0.2,
    metalness: 0,
    transparent: true,
    opacity: Math.max(0, Math.min(1, opacity)),
    blending: THREE.NormalBlending,
    depthWrite: false,
    toneMapped: true,
  })
  material.userData['pfxHealingFocal'] = 'restorative-star'
  return material
}

/** A low-poly luminous vine gives the leaf field an unmistakable 3D path. */
export function createPfxHealingVinePoint(progress: number): [number, number, number] {
  const normalized = THREE.MathUtils.clamp(progress, 0, 1)
  const angle = normalized * Math.PI * 2.3
  const radius = 0.22 + Math.sin(normalized * Math.PI) * 0.56
  const depthRadius = radius * 0.55
  return [
    roundMetric(Math.cos(angle) * radius),
    roundMetric(-0.82 + normalized * 1.72),
    roundMetric(Math.sin(angle) * depthRadius),
  ]
}

export function createPfxHealingVineGeometry(): THREE.TubeGeometry {
  const points: THREE.Vector3[] = []
  for (let step = 0; step <= 32; step++) {
    const progress = step / 32
    points.push(new THREE.Vector3(...createPfxHealingVinePoint(progress)))
  }
  return new THREE.TubeGeometry(new THREE.CatmullRomCurve3(points), 40, 0.034, 8, false)
}

export function createPfxHealingFocalGeometry(): THREE.ExtrudeGeometry {
  const shape = new THREE.Shape()
  for (let point = 0; point < 8; point++) {
    const angle = -Math.PI / 2 + point * Math.PI / 4
    const radius = point % 2 === 0 ? 0.2 : 0.055
    const x = Math.cos(angle) * radius
    const y = Math.sin(angle) * radius
    if (point === 0) shape.moveTo(x, y)
    else shape.lineTo(x, y)
  }
  shape.closePath()
  const geometry = new THREE.ExtrudeGeometry(shape, {
    depth: 0.07,
    steps: 1,
    bevelEnabled: true,
    bevelSegments: 1,
    bevelSize: 0.012,
    bevelThickness: 0.012,
  })
  geometry.translate(0, 0, -0.035)
  geometry.computeVertexNormals()
  return geometry
}

export function createPfxHealingSparkleGeometry(): THREE.OctahedronGeometry {
  return new THREE.OctahedronGeometry(0.055, 0)
}

export interface PfxHealingSparklePose {
  position: [number, number, number]
  rotation: [number, number, number]
  scale: number
}

/** Eight tiny healing glints rise on the authored vines, never as loose rain. */
export function createPfxHealingSparkleLayout(elapsedSeconds: number): PfxHealingSparklePose[] {
  return Array.from({ length: 12 }, (_, index) => {
    const rise = (elapsedSeconds / 1.2 + index / 12) % 1
    const [baseX, y, baseZ] = createPfxHealingVinePoint(rise)
    const side = index % 2 === 0 ? 1 : -1
    return {
      position: [roundMetric(baseX * side), y, roundMetric(baseZ * side)],
      rotation: [roundMetric(elapsedSeconds * 1.7 + index), roundMetric(index * 0.71), roundMetric(elapsedSeconds * 2.1)],
      scale: roundMetric(0.45 + Math.sin(rise * Math.PI) * 0.22),
    }
  })
}

export interface PfxHealingGlyphPose {
  role: 'hero' | 'satellite'
  position: [number, number, number]
  rotationY: number
  scale: number
}

/** Fast readable anticipation, a held peak, then a decisively sharper recovery. */
export function createPfxHealingRestorationPulse(elapsedSeconds: number): number {
  const beat = (Math.max(0, elapsedSeconds) % 1.1) / 1.1
  const activeWindow = 0.36
  if (beat >= activeWindow) return 0
  const progress = Math.min(1, beat / activeWindow)
  const sine = Math.sin(progress * Math.PI)
  return roundMetric(Math.pow(sine, progress < 0.5 ? 0.55 : 2.2))
}

/**
 * A calm 54 BPM restoration beat. A faceted life seed owns the read;
 * a true-geometry vine-and-leaf envelope rises around it instead of forming a random
 * green cloud. The short active window gives every loop a visible
 * onset/peak/recovery while the ground runes carry continuity at rest.
 */
export function createPfxHealingGlyphLayout(elapsedSeconds: number): PfxHealingGlyphPose[] {
  const pulse = createPfxHealingRestorationPulse(elapsedSeconds)
  const heroScale = Math.max(0.025, pulse * 1.05)
  return [{
    role: 'hero',
    position: [0, -0.1, 0],
    rotationY: elapsedSeconds * 0.18,
    scale: roundMetric(heroScale),
  }]
}

export interface PfxHealingLeafHelixPose {
  position: [number, number, number]
  rotation: [number, number, number]
  scale: number
}

export function createPfxHealingLeafProgress(elapsedSeconds: number, index: number, count: number): number {
  const safeCount = Math.max(1, Math.floor(count))
  const hash = Math.sin((index + 1) * 12.9898) * 43758.5453
  const jitter = (hash - Math.floor(hash) - 0.5) * 0.035
  const progress = elapsedSeconds / 1.5 + index / safeCount + jitter
  return roundMetric(((progress % 1) + 1) % 1)
}

/** Twenty-two true-geometry leaves registered to one botanical spiral: one draw call. */
export function createPfxHealingLeafHelixLayout(elapsedSeconds: number): PfxHealingLeafHelixPose[] {
  const pulse = createPfxHealingRestorationPulse(elapsedSeconds)
  const cadenceScale = 0.28 + pulse * 0.72
  const poses: PfxHealingLeafHelixPose[] = []
  for (let step = 0; step < 22; step++) {
    const rise = createPfxHealingLeafProgress(elapsedSeconds, step, 22)
    const angle = rise * Math.PI * 2.4 + elapsedSeconds * 0.7
    const [x, y, z] = createPfxHealingVinePoint(rise)
    const scaleHash = Math.sin((step + 3) * 31.763) * 17453.21
    const variation = scaleHash - Math.floor(scaleHash)
    const scale = (0.3 + variation * 0.22 + Math.sin(rise * Math.PI) * 0.07) * cadenceScale
    poses.push({
      position: [roundMetric(x), roundMetric(y), roundMetric(z)],
      rotation: [roundMetric((step % 2 === 0 ? 1 : -1) * (0.12 + rise * 0.18)), roundMetric(-angle + Math.PI / 2), step % 2 === 0 ? 0.38 : -0.38],
      scale: roundMetric(scale),
    })
  }
  return poses
}

export function createPfxHealingGlyphGeometry(): THREE.ExtrudeGeometry {
  const shape = new THREE.Shape()
  shape.moveTo(0, 0)
  shape.bezierCurveTo(0.2, 0.12, 0.18, 0.42, 0, 0.58)
  shape.bezierCurveTo(-0.18, 0.42, -0.2, 0.12, 0, 0)
  shape.closePath()
  const geometry = new THREE.ExtrudeGeometry(shape, {
    depth: 0.055,
    steps: 1,
    bevelEnabled: true,
    bevelSegments: 2,
    bevelSize: 0.014,
    bevelThickness: 0.014,
    curveSegments: 8,
  })
  geometry.translate(0, 0, -0.0275)
  geometry.computeVertexNormals()
  return geometry
}

/** Rounded aperture depth around the authored XY portal plane. A raw
 * cylinder/cone exposes a frustum; a concave bowl collapses into a sail at
 * exact side view. The toroidal rim keeps a bounded, honest cross-section. */
export function createPfxPortalThroatGeometry(): THREE.TorusGeometry {
  const geometry = new THREE.TorusGeometry(0.66, 0.12, 24, 64)
  geometry.computeVertexNormals()
  geometry.userData['pfxPortalThroatGeometry'] = 'rounded-aperture-rim'
  return geometry
}

/** Held projectiles still need a readable beat in a static review packet:
 * the head stays locked to the gameplay origin while the wake grows, holds,
 * then erodes back to the rear taper before the seamless loop restarts. */
export function createPfxProjectileWakeEnvelope(cycle: number): number {
  const p = Math.max(0, Math.min(1, cycle))
  const pulse = (p * 6) % 1
  if (pulse < 0.35) {
    const grow = pulse / 0.35
    return roundMetric(0.08 + (grow * grow * (3 - 2 * grow)) * 0.92)
  }
  if (pulse <= 0.55) return 1
  const recovery = Math.max(0, Math.min(1, (pulse - 0.55) / 0.3))
  return roundMetric(1 - recovery * recovery * (3 - 2 * recovery))
}

/** One-shot voltage handoff for a movement wake. A short source charge is
 * present on frame zero, the bolt races to full reach, then the oldest tail
 * charge erodes toward the source before a clean rest. */
export function createPfxElectricTrailLifecycle(cycle: number): {
  reach: number
  decay: number
  intensity: number
} {
  const phase = THREE.MathUtils.clamp(cycle, 0, 1)
  const smooth = (value: number) => value * value * (3 - 2 * value)
  if (phase < 0.065) {
    const rise = smooth(phase / 0.065)
    return {
      reach: roundMetric(0.32 + rise * 0.68),
      decay: 0,
      intensity: roundMetric(0.65 + rise * 0.35),
    }
  }
  if (phase < 0.09) return { reach: 1, decay: 0, intensity: 1 }
  if (phase < 0.2) {
    const recovery = smooth((phase - 0.09) / 0.11)
    return {
      reach: 1,
      decay: roundMetric(recovery),
      intensity: roundMetric(1 - recovery),
    }
  }
  return { reach: 0.08, decay: 1, intensity: 0 }
}

/** One closed sculpted plasma wake. A short head collar survives the axial
 * camera; scalloped taper and an offset spine break the stock cone without
 * turning the directional trail into ornamental braids or detached cards. */
export function createPfxProjectileWakeGeometry(
  radialSegments = 20,
  axialSegments = 28,
): THREE.BufferGeometry {
  const radial = Math.max(8, Math.floor(radialSegments))
  const axial = Math.max(12, Math.floor(axialSegments))
  const positions: number[] = []
  const normals: number[] = []
  const uvs: number[] = []
  const indices: number[] = []
  const strandCount = 1
  const headRadius = 0.62
  const tailRadius = 0.025
  const headX = 1.1
  const length = 2.7

  let tailY = 0
  let tailZ = 0
  for (let ring = 0; ring <= axial; ring += 1) {
    const t = ring / axial
    const x = headX - length * t
    const centerY = Math.sin(t * Math.PI * 2.2) * 0.09 * Math.pow(t, 0.7)
    const centerZ = Math.cos(t * Math.PI * 1.6) * 0.07 * Math.pow(t, 0.8)
    tailY = centerY
    tailZ = centerZ
    const baseRadius = tailRadius + (0.34 - tailRadius) * Math.pow(1 - t, 0.75)
    const headCollar = 0.22 * Math.exp(-t * 22)
    const scallop = 0.9 + Math.sin(t * Math.PI * 6 + 0.8) * 0.1 * Math.pow(Math.sin(Math.PI * t), 0.6)
    const radius = (baseRadius + headCollar) * scallop
    for (let side = 0; side < radial; side += 1) {
      const angle = (side / radial) * Math.PI * 2
      const ny = Math.cos(angle)
      const nz = Math.sin(angle)
      const headLobe = 1 + Math.sin(angle * 3 + 0.4) * 0.1 * Math.exp(-t * 12)
      positions.push(x, centerY + ny * radius * headLobe, centerZ + nz * radius * headLobe)
      normals.push(0, ny, nz)
      uvs.push(1 - t, side / radial)
    }
  }
  for (let ring = 0; ring < axial; ring += 1) {
    for (let side = 0; side < radial; side += 1) {
      const next = (side + 1) % radial
      const a = ring * radial + side
      const b = ring * radial + next
      const c = (ring + 1) * radial + next
      const d = (ring + 1) * radial + side
      indices.push(a, d, b, b, d, c)
    }
  }
  const headCenter = positions.length / 3
  positions.push(headX, 0, 0)
  normals.push(1, 0, 0)
  uvs.push(1, 0.5)
  const tailCenter = positions.length / 3
  positions.push(headX - length, tailY, tailZ)
  normals.push(-1, 0, 0)
  uvs.push(0, 0.5)
  const tailStart = axial * radial
  for (let side = 0; side < radial; side += 1) {
    const next = (side + 1) % radial
    indices.push(headCenter, next, side)
    indices.push(tailCenter, tailStart + side, tailStart + next)
  }

  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.setIndex(indices)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxProjectileWakeGeometry'] = 'closed-tapered-volumetric-plasma-wake'
  geometry.userData['pfxProjectileWakeClosedCaps'] = true
  geometry.userData['pfxProjectileWakeStrandCount'] = strandCount
  geometry.userData['pfxProjectileWakeRadialSegments'] = radial
  geometry.userData['pfxProjectileWakeHeadLobes'] = 3
  geometry.userData['pfxProjectileWakeHeadRadius'] = headRadius
  geometry.userData['pfxProjectileWakeTailRadius'] = tailRadius
  geometry.userData['pfxProjectileWakeDrawCalls'] = 1
  return geometry
}

/** A single-draw family of three capped bolt tubes. The dominant spine owns
 * the travel vector; two shorter forks leave that spine in different depth
 * planes so a side camera sees honest cross-section and parallax instead of
 * the baseline crossed-card asterisk. */
export function createPfxElectricWakeGeometry(radialSegments = 10): THREE.BufferGeometry {
  const radial = Math.max(8, Math.floor(radialSegments))
  const positions: number[] = []
  const normals: number[] = []
  const uvs: number[] = []
  const indices: number[] = []
  type BoltNode = { point: THREE.Vector3; u: number; radius: number }

  const appendTube = (nodes: BoltNode[], strand: number) => {
    const vertexStart = positions.length / 3
    const tangents = nodes.map((_node, nodeIndex) => {
      const previous = nodes[Math.max(0, nodeIndex - 1)]!.point
      const next = nodes[Math.min(nodes.length - 1, nodeIndex + 1)]!.point
      return next.clone().sub(previous).normalize()
    })
    const firstReference = Math.abs(tangents[0]!.y) < 0.86
      ? new THREE.Vector3(0, 1, 0)
      : new THREE.Vector3(0, 0, 1)
    let transportedAxis = new THREE.Vector3().crossVectors(tangents[0]!, firstReference).normalize()
    for (let nodeIndex = 0; nodeIndex < nodes.length; nodeIndex += 1) {
      const node = nodes[nodeIndex]!
      const tangent = tangents[nodeIndex]!
      if (nodeIndex > 0) {
        // Parallel-transport the previous ring frame onto the new tangent's
        // normal plane. Independent per-node cross products can flip by 90°
        // at a lightning kink, stretching the connecting quads into sails.
        const projected = transportedAxis.clone().addScaledVector(tangent, -transportedAxis.dot(tangent))
        if (projected.lengthSq() < 1e-6) {
          const fallback = Math.abs(tangent.y) < 0.86
            ? new THREE.Vector3(0, 1, 0)
            : new THREE.Vector3(0, 0, 1)
          transportedAxis = new THREE.Vector3().crossVectors(tangent, fallback).normalize()
        } else {
          transportedAxis = projected.normalize()
        }
      }
      const axisA = transportedAxis
      const axisB = new THREE.Vector3().crossVectors(tangent, axisA).normalize()
      for (let side = 0; side < radial; side += 1) {
        const angle = (side / radial) * Math.PI * 2
        const radialNormal = axisA.clone().multiplyScalar(Math.cos(angle)).addScaledVector(axisB, Math.sin(angle)).normalize()
        const lobe = 1 + Math.sin(angle * 3 + strand * 1.7 + node.u * 9) * 0.08
        const position = node.point.clone().addScaledVector(radialNormal, node.radius * lobe)
        positions.push(position.x, position.y, position.z)
        normals.push(radialNormal.x, radialNormal.y, radialNormal.z)
        // Two UV units per strand let the shader recover both an integer
        // strand id and a wrapped angular coordinate without another buffer.
        uvs.push(node.u, strand * 2 + (side / radial) * 2)
      }
    }
    for (let ring = 0; ring < nodes.length - 1; ring += 1) {
      for (let side = 0; side < radial; side += 1) {
        const nextSide = (side + 1) % radial
        const a = vertexStart + ring * radial + side
        const b = vertexStart + ring * radial + nextSide
        const c = vertexStart + (ring + 1) * radial + nextSide
        const d = vertexStart + (ring + 1) * radial + side
        indices.push(a, d, b, b, d, c)
      }
    }
    const startCenter = positions.length / 3
    const startTangent = nodes[1]!.point.clone().sub(nodes[0]!.point).normalize().multiplyScalar(-1)
    positions.push(nodes[0]!.point.x, nodes[0]!.point.y, nodes[0]!.point.z)
    normals.push(startTangent.x, startTangent.y, startTangent.z)
    uvs.push(nodes[0]!.u, strand * 2 + 1)
    const endCenter = positions.length / 3
    const last = nodes.length - 1
    const endTangent = nodes[last]!.point.clone().sub(nodes[last - 1]!.point).normalize()
    positions.push(nodes[last]!.point.x, nodes[last]!.point.y, nodes[last]!.point.z)
    normals.push(endTangent.x, endTangent.y, endTangent.z)
    uvs.push(nodes[last]!.u, strand * 2 + 1)
    const endRing = vertexStart + last * radial
    for (let side = 0; side < radial; side += 1) {
      const nextSide = (side + 1) % radial
      indices.push(startCenter, vertexStart + nextSide, vertexStart + side)
      indices.push(endCenter, endRing + side, endRing + nextSide)
    }
  }

  const node = (x: number, y: number, z: number, u: number, radius: number): BoltNode => ({
    point: new THREE.Vector3(x, y, z), u, radius,
  })
  const main = [
    node(1.02, 0, 0, 0, 0.13),
    node(0.72, 0.06, 0.04, 0.1, 0.12),
    node(0.42, -0.11, 0.16, 0.2, 0.12),
    node(0.12, 0.1, 0.12, 0.3, 0.11),
    node(-0.18, -0.08, 0.28, 0.4, 0.1),
    node(-0.48, 0.11, 0.24, 0.5, 0.09),
    node(-0.78, -0.05, 0.4, 0.6, 0.078),
    node(-1.08, 0.09, 0.36, 0.7, 0.065),
    node(-1.38, -0.12, 0.54, 0.8, 0.05),
    node(-1.68, 0.03, 0.5, 0.9, 0.04),
    node(-2.04, -0.04, 0.62, 1, 0.025),
  ]
  const upperFork = [
    node(0.12, 0.1, 0.12, 0.3, 0.09),
    node(-0.16, 0.3, 0.32, 0.43, 0.07),
    node(-0.48, 0.47, 0.55, 0.58, 0.05),
    node(-0.84, 0.6, 0.72, 0.73, 0.022),
  ]
  const lowerFork = [
    node(-0.18, -0.08, 0.28, 0.4, 0.075),
    node(-0.5, -0.25, 0.05, 0.54, 0.06),
    node(-0.86, -0.43, -0.2, 0.7, 0.04),
    node(-1.26, -0.57, -0.42, 0.86, 0.02),
  ]
  appendTube(main, 0)
  appendTube(upperFork, 1)
  appendTube(lowerFork, 2)

  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.setIndex(indices)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxElectricWakeGeometry'] = 'closed-forked-directional-bolt-volume'
  geometry.userData['pfxElectricWakeClosedCaps'] = true
  geometry.userData['pfxElectricWakeFrameTransport'] = 'parallel-transport'
  geometry.userData['pfxElectricWakeMainDepthDrift'] = 0.62
  geometry.userData['pfxElectricWakeMainDepthOscillation'] = 0.08
  geometry.userData['pfxElectricWakeStrandCount'] = 3
  geometry.userData['pfxElectricWakeRadialSegments'] = radial
  geometry.userData['pfxElectricWakeHeadRadius'] = 0.13
  geometry.userData['pfxElectricWakeTailRadius'] = 0.025
  geometry.userData['pfxElectricWakeDrawCalls'] = 1
  return geometry
}

/** One irregular liquid surface, its closed edge skirt, and all bubbling
 * hemispheres share a single indexed draw. This keeps the pool grounded and
 * gives the acid real parallax without spending one draw per bubble. */
export function createPfxAcidPoolGeometry(boundarySegments = 48, radialRings = 6): THREE.BufferGeometry {
  const segments = Math.max(40, Math.floor(boundarySegments))
  const rings = Math.max(4, Math.floor(radialRings))
  const positions: number[] = [0, 0, 0]
  const normals: number[] = [0, 1, 0]
  const uvs: number[] = [0.5, 0.5]
  const indices: number[] = []
  const boundaryRadius = (angle: number) => 1 + Math.sin(angle * 3 + 0.4) * 0.075 + Math.sin(angle * 7 - 0.8) * 0.045 + Math.cos(angle * 11) * 0.025
  const ringStarts: number[] = []

  for (let ring = 1; ring <= rings; ring += 1) {
    ringStarts.push(positions.length / 3)
    const fraction = ring / rings
    for (let segment = 0; segment < segments; segment += 1) {
      const angle = (segment / segments) * Math.PI * 2
      const radius = boundaryRadius(angle) * fraction
      const x = Math.cos(angle) * radius * 1.12
      const z = Math.sin(angle) * radius * 0.82
      const y = Math.sin(angle * 2.3 + fraction * 1.7) * 0.006 * fraction
      positions.push(x, y, z)
      normals.push(0, 1, 0)
      uvs.push(x / 2.5 + 0.5, z / 1.9 + 0.5)
    }
  }
  const firstRing = ringStarts[0]!
  for (let segment = 0; segment < segments; segment += 1) {
    indices.push(0, firstRing + segment, firstRing + (segment + 1) % segments)
  }
  for (let ring = 0; ring < rings - 1; ring += 1) {
    const inner = ringStarts[ring]!
    const outer = ringStarts[ring + 1]!
    for (let segment = 0; segment < segments; segment += 1) {
      const next = (segment + 1) % segments
      indices.push(inner + segment, outer + segment, inner + next)
      indices.push(inner + next, outer + segment, outer + next)
    }
  }

  const boundaryTop = positions.length / 3
  for (let segment = 0; segment < segments; segment += 1) {
    const angle = (segment / segments) * Math.PI * 2
    const radius = boundaryRadius(angle)
    const x = Math.cos(angle) * radius * 1.12
    const z = Math.sin(angle) * radius * 0.82
    const edgeNormal = new THREE.Vector3(x / 1.12, 0.18, z / 0.82).normalize()
    positions.push(x, 0, z, x, -0.075, z)
    normals.push(edgeNormal.x, edgeNormal.y, edgeNormal.z, edgeNormal.x, edgeNormal.y, edgeNormal.z)
    const u = segment / segments
    uvs.push(u, 1, u, 0)
  }
  for (let segment = 0; segment < segments; segment += 1) {
    const next = (segment + 1) % segments
    const top = boundaryTop + segment * 2
    const bottom = top + 1
    const nextTop = boundaryTop + next * 2
    const nextBottom = nextTop + 1
    indices.push(top, bottom, nextTop, nextTop, bottom, nextBottom)
  }

  const bubbles: Array<[number, number, number, number]> = [
    [-0.48, 0.18, 0.16, 1], [0.34, -0.26, 0.13, 0.82], [0.08, 0.36, 0.11, 0.68],
    [0.58, 0.18, 0.085, 0.58], [-0.18, -0.42, 0.1, 0.72], [0.02, -0.08, 0.075, 0.5],
  ]
  const bubbleSides = 12
  const bubbleLatitudes = 5
  for (const [centerX, centerZ, radius, heightScale] of bubbles) {
    const bubbleStart = positions.length / 3
    for (let latitude = 0; latitude <= bubbleLatitudes; latitude += 1) {
      const phi = (latitude / bubbleLatitudes) * Math.PI * 0.5
      const ringRadius = Math.cos(phi) * radius
      const y = Math.sin(phi) * radius * heightScale
      for (let side = 0; side < bubbleSides; side += 1) {
        const theta = (side / bubbleSides) * Math.PI * 2
        const nx = Math.cos(theta) * Math.cos(phi)
        const ny = Math.sin(phi)
        const nz = Math.sin(theta) * Math.cos(phi)
        positions.push(centerX + nx * radius, y, centerZ + nz * radius)
        normals.push(nx, ny, nz)
        uvs.push(side / bubbleSides, latitude / bubbleLatitudes)
      }
    }
    for (let latitude = 0; latitude < bubbleLatitudes; latitude += 1) {
      for (let side = 0; side < bubbleSides; side += 1) {
        const next = (side + 1) % bubbleSides
        const a = bubbleStart + latitude * bubbleSides + side
        const b = bubbleStart + latitude * bubbleSides + next
        const c = bubbleStart + (latitude + 1) * bubbleSides + next
        const d = bubbleStart + (latitude + 1) * bubbleSides + side
        indices.push(a, d, b, b, d, c)
      }
    }
  }

  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.setIndex(indices)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxAcidPoolGeometry'] = 'irregular-skirted-pool-with-integrated-domes'
  geometry.userData['pfxAcidPoolDrawCalls'] = 1
  geometry.userData['pfxAcidPoolBoundarySegments'] = segments
  geometry.userData['pfxAcidPoolBubbleCount'] = bubbles.length
  geometry.userData['pfxAcidPoolClosedSkirt'] = true
  return geometry
}

/** A translucent pressure wedge and three swept boundary streamlines folded
 * into one draw. The broad intake contracts toward one unmistakable contact
 * point and every secondary line follows that same flow axis. */
export function createPfxWindPressureGeometry(radialSegments = 8, axialSegments = 24): THREE.BufferGeometry {
  const radial = Math.max(6, Math.floor(radialSegments))
  const axial = Math.max(16, Math.floor(axialSegments))
  const tipRadius = 0.01
  const positions: number[] = []
  const normals: number[] = []
  const colors: number[] = []
  const uvs: number[] = []
  const indices: number[] = []
  const paths: Array<{ width: number; points: Array<[number, number, number]> }> = [
    { width: 1, points: [[-1.48, 0.3, -0.1], [-0.88, 0.46, -0.08], [-0.24, 0.34, -0.02], [0.4, 0.12, 0.04], [1.08, 0.2, 0.1]] },
    { width: 0.86, points: [[-1.4, -0.04, 0.2], [-0.78, 0.03, 0.24], [-0.16, 0.06, 0.15], [0.46, 0.03, 0.05], [1.14, -0.06, 0.12]] },
    { width: 0.78, points: [[-1.3, -0.32, -0.16], [-0.72, -0.22, -0.2], [-0.12, -0.14, -0.1], [0.48, -0.04, 0], [1.02, -0.16, 0.16]] },
  ]
  const cool = new THREE.Color('#9aadaf')
  const hot = new THREE.Color('#f0f5f2')

  // The gust body is an elliptical pressure shell: broad and soft at the
  // intake, sharply compressed at contact. A slight vertical/depth drift
  // keeps it volumetric from oblique cameras without obscuring its direction.
  const shellRadial = Math.max(12, radial * 2)
  const shellAxial = Math.max(18, axial)
  const shellStart = positions.length / 3
  for (let ring = 0; ring <= shellAxial; ring += 1) {
    const t = ring / shellAxial
    const eased = t * t * (3 - 2 * t)
    const x = THREE.MathUtils.lerp(-1.42, 0.38, t)
    const centerY = 0.04 + Math.sin(t * Math.PI) * 0.035
    const centerZ = Math.sin(t * Math.PI) * 0.045
    const radiusY = THREE.MathUtils.lerp(0.52, 0.115, eased)
    const radiusZ = THREE.MathUtils.lerp(0.39, 0.1, eased)
    const shellColor = cool.clone().lerp(hot, Math.pow(t, 2.2) * 0.9)
    for (let side = 0; side < shellRadial; side += 1) {
      const angle = (side / shellRadial) * Math.PI * 2
      const cos = Math.cos(angle)
      const sin = Math.sin(angle)
      positions.push(x, centerY + cos * radiusY, centerZ + sin * radiusZ)
      const normal = new THREE.Vector3(0.22, cos / radiusY, sin / radiusZ).normalize()
      normals.push(normal.x, normal.y, normal.z)
      colors.push(shellColor.r, shellColor.g, shellColor.b)
      uvs.push(t, side / shellRadial)
    }
  }
  for (let ring = 0; ring < shellAxial; ring += 1) {
    for (let side = 0; side < shellRadial; side += 1) {
      const next = (side + 1) % shellRadial
      const a = shellStart + ring * shellRadial + side
      const b = shellStart + ring * shellRadial + next
      const c = shellStart + (ring + 1) * shellRadial + next
      const d = shellStart + (ring + 1) * shellRadial + side
      indices.push(a, d, b, b, d, c)
    }
  }

  for (const [streamIndex, path] of paths.entries()) {
    const curve = new THREE.CatmullRomCurve3(path.points.map((point) => new THREE.Vector3(...point)), false, 'centripetal')
    const centers = Array.from({ length: axial + 1 }, (_, index) => curve.getPoint(index / axial))
    const tangents = Array.from({ length: axial + 1 }, (_, index) => curve.getTangent(index / axial).normalize())
    const preferredWidth = streamIndex === 1 ? new THREE.Vector3(0, 0.55, 1) : new THREE.Vector3(0, 1, streamIndex === 2 ? 0.28 : -0.12)
    let transportedAxis = preferredWidth.clone().addScaledVector(tangents[0]!, -preferredWidth.dot(tangents[0]!)).normalize()
    const vertexStart = positions.length / 3
    for (let ring = 0; ring <= axial; ring += 1) {
      const t = ring / axial
      const tangent = tangents[ring]!
      if (ring > 0) {
        const projected = transportedAxis.clone().addScaledVector(tangent, -transportedAxis.dot(tangent))
        if (projected.lengthSq() > 1e-6) transportedAxis = projected.normalize()
      }
      const width = tipRadius + Math.pow(Math.sin(Math.PI * t), 0.72) * 0.074 * path.width
      const faceNormal = new THREE.Vector3().crossVectors(tangent, transportedAxis).normalize()
      const brightness = 0.2 + Math.pow(Math.sin(Math.PI * t), 2.2) * 0.8
      const color = cool.clone().lerp(hot, brightness)
      for (const side of [-1, 1] as const) {
        const point = centers[ring]!.clone().addScaledVector(transportedAxis, width * side)
        positions.push(point.x, point.y, point.z)
        normals.push(faceNormal.x, faceNormal.y, faceNormal.z)
        colors.push(color.r, color.g, color.b)
        uvs.push(t, 1 + streamIndex + (side + 1) * 0.25)
      }
    }
    for (let ring = 0; ring < axial; ring += 1) {
      const a = vertexStart + ring * 2
      const b = a + 1
      const c = vertexStart + (ring + 1) * 2 + 1
      const d = vertexStart + (ring + 1) * 2
      indices.push(a, d, b, b, d, c)
    }
  }

  // An open toroidal pressure crescent replaces a generic luminous core. It
  // is edge-on from the primary view but exposes a broad compressed-air
  // cross-section when the camera looks down the travel axis.
  const crescentArc = Math.PI * 1.3
  const crescentSegments = 30
  const crescentSides = Math.max(6, radial)
  const crescentStart = positions.length / 3
  const crescentRadius = 0.43
  const crescentTube = 0.028
  for (let segment = 0; segment <= crescentSegments; segment += 1) {
    const t = segment / crescentSegments
    const theta = -crescentArc * 0.5 + t * crescentArc
    const radialY = Math.cos(theta)
    const radialZ = Math.sin(theta)
    for (let side = 0; side < crescentSides; side += 1) {
      const phi = (side / crescentSides) * Math.PI * 2
      const axialNormal = Math.cos(phi)
      const ringNormal = Math.sin(phi)
      const ringRadius = crescentRadius + ringNormal * crescentTube
      positions.push(
        0.38 + axialNormal * crescentTube,
        0.045 + radialY * ringRadius,
        radialZ * ringRadius,
      )
      normals.push(axialNormal, radialY * ringNormal, radialZ * ringNormal)
      const brightness = 0.52 + Math.sin(t * Math.PI) * 0.48
      const color = cool.clone().lerp(hot, brightness)
      colors.push(color.r, color.g, color.b)
      uvs.push(t, 5 + side / crescentSides)
    }
  }
  for (let segment = 0; segment < crescentSegments; segment += 1) {
    for (let side = 0; side < crescentSides; side += 1) {
      const next = (side + 1) % crescentSides
      const a = crescentStart + segment * crescentSides + side
      const b = crescentStart + segment * crescentSides + next
      const c = crescentStart + (segment + 1) * crescentSides + next
      const d = crescentStart + (segment + 1) * crescentSides + side
      indices.push(a, d, b, b, d, c)
    }
  }

  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.setIndex(indices)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxWindPressureGeometry'] = 'single-draw-pressure-wedge-with-swept-streamlines'
  geometry.userData['pfxWindPressureStreamCount'] = paths.length
  geometry.userData['pfxWindPressureStreamProfile'] = 'parallel-swept-ribbons'
  geometry.userData['pfxWindPressureShell'] = 'wide-tail-to-contact-wedge'
  geometry.userData['pfxWindPressureFlowAxis'] = [1, 0.08, 0.04]
  geometry.userData['pfxWindPressureTaperedEnds'] = true
  geometry.userData['pfxWindPressureContactCore'] = 'open-pressure-crescent'
  geometry.userData['pfxWindPressureCrescentArc'] = crescentArc
  geometry.userData['pfxWindPressureCrescentTube'] = crescentTube
  geometry.userData['pfxWindPressureTipRadius'] = tipRadius
  geometry.userData['pfxWindPressureDrawCalls'] = 1
  return geometry
}

export function createPfxWindPressureMaterial(
  opacity: number,
  color: THREE.ColorRepresentation,
): THREE.ShaderMaterial {
  return new THREE.ShaderMaterial({
    uniforms: {
      uColor: { value: new THREE.Color(color) },
      uOpacity: { value: THREE.MathUtils.clamp(opacity, 0, 1) },
    },
    vertexColors: true,
    transparent: true,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    side: THREE.DoubleSide,
    toneMapped: false,
    vertexShader: `
      varying vec3 vColor;
      varying vec3 vNormal;
      varying vec3 vViewDirection;
      varying vec2 vUv;
      void main() {
        vColor = color;
        vUv = uv;
        vec4 viewPosition = modelViewMatrix * vec4(position, 1.0);
        vNormal = normalize(normalMatrix * normal);
        vViewDirection = normalize(-viewPosition.xyz);
        gl_Position = projectionMatrix * viewPosition;
      }
    `,
    fragmentShader: `
      uniform vec3 uColor;
      uniform float uOpacity;
      varying vec3 vColor;
      varying vec3 vNormal;
      varying vec3 vViewDirection;
      varying vec2 vUv;
      void main() {
        float rim = pow(1.0 - abs(dot(normalize(vNormal), normalize(vViewDirection))), 1.35);
        float body = smoothstep(0.0, 0.15, vUv.x) * (1.0 - smoothstep(0.7, 1.0, vUv.x));
        float isCrescent = step(4.0, vUv.y);
        float isStream = step(1.0, vUv.y) * (1.0 - isCrescent);
        float shellAlpha = mix(0.02 + rim * 0.1, 0.08 + rim * 0.15, body);
        float alpha = mix(shellAlpha, 0.52 + rim * 0.28, isStream);
        alpha = mix(alpha, 0.18 + rim * 0.34, isCrescent);
        vec3 shaded = uColor * vColor * (0.72 + rim * 0.78 + body * 0.24);
        gl_FragColor = vec4(shaded, alpha * uOpacity);
      }
    `,
  })
}

/** Four closed flow streamlines, an open tail-to-front pressure scoop, and two
 * grounded dust wakes merged into one mobile draw. The clean leading/trailing
 * asymmetry keeps the gust directional without introducing a projectile cap. */
export function createPfxWindBeamPressureGeometry(): THREE.BufferGeometry {
  const positions: number[] = []
  const normals: number[] = []
  const colors: number[] = []
  const uvs: number[] = []
  const indices: number[] = []
  const flowRise = 0.05
  const flowDepth = 0.24
  const arcHeight = 0.12
  const axialSegments = 11
  const crossSegments = 6
  const streams = [
    { y: -0.02, z: -0.02, ay: 0.036, az: 0.03, bendY: 0.04, bendZ: -0.025, depthSlope: 0.05, phase: 0.7, width: 1.05, start: -1.94, end: 2.08 },
    { y: 0.48, z: 0.2, ay: 0.035, az: 0.032, bendY: 0.08, bendZ: -0.03, depthSlope: 0.015, phase: 2.4, width: 0.7, start: -1.74, end: 1.88 },
    { y: -0.44, z: -0.18, ay: 0.038, az: 0.034, bendY: -0.06, bendZ: 0.035, depthSlope: -0.02, phase: 4.1, width: 0.58, start: -1.62, end: 1.7 },
    { y: 0.2, z: -0.3, ay: 0.04, az: 0.04, bendY: 0.03, bendZ: 0.045, depthSlope: 0.03, phase: 5.35, width: 0.42, start: -1.36, end: 1.48 },
  ] as const
  const cool = new THREE.Color('#c5cdd2')
  const hot = new THREE.Color('#e8f6f7')
  const laneTints = ['#f5fcfd', '#dbe8ea', '#c8dadd', '#afc8cc'].map((tint) => new THREE.Color(tint))
  const arcScales = [0.35, 1.15, -0.8, 0.55] as const
  const harmonicY = [0.018, 0.03, -0.028, 0.034] as const
  const harmonicZ = [-0.016, 0.026, -0.024, 0.03] as const

  for (const [streamIndex, stream] of streams.entries()) {
    const arcScale = arcScales[streamIndex]!
    const laneHarmonicY = harmonicY[streamIndex]!
    const laneHarmonicZ = harmonicZ[streamIndex]!
    const vertexStart = positions.length / 3
    for (let ring = 0; ring <= axialSegments; ring += 1) {
      const t = ring / axialSegments
      const envelope = Math.pow(Math.sin(Math.PI * t), 0.62)
      const x = THREE.MathUtils.lerp(stream.start, stream.end, t)
      const sweep = Math.sin(t * Math.PI * 1.18 + stream.phase)
      const settle = Math.sin(t * Math.PI)
      const center = new THREE.Vector3(
        x,
        stream.y * (0.18 + t * 0.82) + sweep * stream.ay * settle + settle * stream.bendY + x * flowRise + Math.sin(t * Math.PI) * arcHeight * arcScale + Math.sin(t * Math.PI * 2 + stream.phase) * laneHarmonicY * settle,
        stream.z * (0.18 + t * 0.82) + Math.cos(t * Math.PI * 1.06 + stream.phase) * stream.az * settle + settle * stream.bendZ + x * stream.depthSlope + Math.cos(t * Math.PI * 2.4 + stream.phase) * laneHarmonicZ * settle,
      )
      const nextT = Math.min(1, t + 0.002)
      const nextX = THREE.MathUtils.lerp(stream.start, stream.end, nextT)
      const nextSweep = Math.sin(nextT * Math.PI * 1.18 + stream.phase)
      const nextSettle = Math.sin(nextT * Math.PI)
      const next = new THREE.Vector3(
        nextX,
        stream.y * (0.18 + nextT * 0.82) + nextSweep * stream.ay * nextSettle + nextSettle * stream.bendY + nextX * flowRise + Math.sin(nextT * Math.PI) * arcHeight * arcScale + Math.sin(nextT * Math.PI * 2 + stream.phase) * laneHarmonicY * nextSettle,
        stream.z * (0.18 + nextT * 0.82) + Math.cos(nextT * Math.PI * 1.06 + stream.phase) * stream.az * nextSettle + nextSettle * stream.bendZ + nextX * stream.depthSlope + Math.cos(nextT * Math.PI * 2.4 + stream.phase) * laneHarmonicZ * nextSettle,
      )
      const tangent = next.sub(center).normalize()
      const normalAxis = new THREE.Vector3(0, 1, 0).addScaledVector(tangent, -tangent.y).normalize()
      const binormal = new THREE.Vector3().crossVectors(tangent, normalAxis).normalize()
      const widthPulse = 0.78 + Math.pow(Math.sin(t * Math.PI * 2 + stream.phase), 2) * 0.22
      const leadingWeight = 0.7 + t * 0.3
      const radiusY = 0.003 + envelope * widthPulse * leadingWeight * 0.068 * stream.width
      const radiusZ = 0.003 + envelope * widthPulse * leadingWeight * 0.05 * stream.width
      const color = cool.clone().lerp(laneTints[streamIndex] ?? hot, 0.32 + t * 0.58)
      for (let side = 0; side < crossSegments; side += 1) {
        const angle = (side / crossSegments) * Math.PI * 2 + Math.PI * 0.25
        const radial = normalAxis.clone().multiplyScalar(Math.cos(angle) * radiusY)
          .addScaledVector(binormal, Math.sin(angle) * radiusZ)
        const point = center.clone().add(radial)
        positions.push(point.x, point.y, point.z)
        normals.push(radial.x, radial.y, radial.z)
        colors.push(color.r, color.g, color.b)
        uvs.push(t, streamIndex + side / crossSegments)
      }
    }
    for (let ring = 0; ring < axialSegments; ring += 1) {
      for (let side = 0; side < crossSegments; side += 1) {
        const nextSide = (side + 1) % crossSegments
        const a = vertexStart + ring * crossSegments + side
        const b = vertexStart + ring * crossSegments + nextSide
        const c = vertexStart + (ring + 1) * crossSegments + nextSide
        const d = vertexStart + (ring + 1) * crossSegments + side
        indices.push(a, d, b, b, d, c)
      }
    }
  }

  // The open shell starts as a narrow tail and opens into a broad leading
  // scoop. It has no end caps, so it reads as displaced air rather than a
  // projectile, while its head/tail ratio supplies an unmistakable +X vector.
  const shellRadialSegments = 10
  const shellAxialSegments = 9
  const shellStart = positions.length / 3
  for (let ring = 0; ring <= shellAxialSegments; ring += 1) {
    const t = ring / shellAxialSegments
    const eased = t * t * (3 - 2 * t)
    const x = THREE.MathUtils.lerp(-1.94, 2.04, t)
    const centerY = Math.sin(t * Math.PI * 1.35) * 0.045 + Math.sin(t * Math.PI) * arcHeight
    const centerZ = Math.sin(t * Math.PI * 1.7 + 0.4) * 0.035
    const turbulence = 0.94 + Math.sin(t * Math.PI * 5.0 + 0.6) * 0.06
    const bodySwell = Math.pow(Math.sin(t * Math.PI), 0.72)
    const radiusY = (THREE.MathUtils.lerp(0.24, 0.54, eased) + bodySwell * 0.18) * turbulence
    const radiusZ = (THREE.MathUtils.lerp(0.2, 0.46, eased) + bodySwell * 0.16) * (2 - turbulence)
    const shellColor = cool.clone().lerp(hot, 0.18 + t * 0.58)
    for (let side = 0; side < shellRadialSegments; side += 1) {
      const angle = (side / shellRadialSegments) * Math.PI * 2
      const cos = Math.cos(angle)
      const sin = Math.sin(angle)
      positions.push(x, centerY + cos * radiusY + x * flowRise, centerZ + sin * radiusZ + x * flowDepth)
      const normal = new THREE.Vector3(0.18 - flowRise * cos / radiusY - flowDepth * sin / radiusZ, cos / radiusY, sin / radiusZ).normalize()
      normals.push(normal.x, normal.y, normal.z)
      colors.push(shellColor.r, shellColor.g, shellColor.b)
      uvs.push(t, 8 + side / shellRadialSegments)
    }
  }
  for (let ring = 0; ring < shellAxialSegments; ring += 1) {
    for (let side = 0; side < shellRadialSegments; side += 1) {
      const nextSide = (side + 1) % shellRadialSegments
      const a = shellStart + ring * shellRadialSegments + side
      const b = shellStart + ring * shellRadialSegments + nextSide
      const c = shellStart + (ring + 1) * shellRadialSegments + nextSide
      const d = shellStart + (ring + 1) * shellRadialSegments + side
      indices.push(a, d, b, b, d, c)
    }
  }

  // Two low, closed three-section wake crests tie the airborne gust to the
  // gameplay plane. A lifted, laterally bowed middle section prevents either
  // wake from resolving into the unfinished straight rail seen in review 959.
  const groundWakeCount = 2
  const groundWakeSections = 5
  const wakeColor = new THREE.Color('#b9dfd8')
  for (let lane = 0; lane < groundWakeCount; lane += 1) {
    const groundY = -0.66 + lane * 0.025
    const wakePoints: THREE.Vector3[] = []
    for (let section = 0; section < groundWakeSections; section += 1) {
      const t = section / (groundWakeSections - 1)
      const crest = Math.sin(t * Math.PI)
      const x = THREE.MathUtils.lerp(-1.72 + lane * 0.06, 1.82 - lane * 0.1, t)
      const laneSign = lane === 0 ? -1 : 1
      const centerZ = laneSign * (0.12 + crest * 0.09) + x * flowDepth
      const halfWidth = THREE.MathUtils.lerp(0.11, 0.035, t) + crest * 0.04
      const height = THREE.MathUtils.lerp(0.028, 0.012, t) + crest * 0.055
      const bottomY = groundY + crest * 0.025
      wakePoints.push(
        new THREE.Vector3(x, bottomY, centerZ - halfWidth),
        new THREE.Vector3(x, bottomY + height, centerZ + Math.sin(t * Math.PI * 3 + lane) * halfWidth * 0.12),
        new THREE.Vector3(x, bottomY, centerZ + halfWidth),
      )
    }
    const wakeTriangles: Array<readonly [number, number, number]> = []
    for (let section = 0; section < groundWakeSections - 1; section += 1) {
      for (let band = 0; band < 2; band += 1) {
        const a = section * 3 + band
        const b = (section + 1) * 3 + band
        const c = (section + 1) * 3 + band + 1
        const d = section * 3 + band + 1
        wakeTriangles.push([a, d, b], [d, c, b])
      }
    }
    for (const triangle of wakeTriangles) {
      const pointA = wakePoints[triangle[0]]!
      const pointB = wakePoints[triangle[1]]!
      const pointC = wakePoints[triangle[2]]!
      const faceNormal = new THREE.Vector3().crossVectors(
        pointB.clone().sub(pointA),
        pointC.clone().sub(pointA),
      ).normalize()
      for (const pointIndex of triangle) {
        const point = wakePoints[pointIndex]!
        const vertexIndex = positions.length / 3
        positions.push(point.x, point.y, point.z)
        normals.push(faceNormal.x, faceNormal.y, faceNormal.z)
        colors.push(wakeColor.r, wakeColor.g, wakeColor.b)
        const section = Math.floor(pointIndex / 3)
        uvs.push(
          THREE.MathUtils.lerp(0.12, 0.84, section / (groundWakeSections - 1)),
          9.0 + lane + (pointIndex % 3) * 0.28,
        )
        indices.push(vertexIndex)
      }
    }
  }

  const geometry = new THREE.BufferGeometry()
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
  geometry.setAttribute('normal', new THREE.Float32BufferAttribute(normals, 3))
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2))
  geometry.setIndex(indices)
  geometry.computeBoundingBox()
  geometry.computeBoundingSphere()
  geometry.userData['pfxWindBeamPressureDrawCalls'] = 1
  geometry.userData['pfxWindBeamPressureStreamCount'] = streams.length
  geometry.userData['pfxWindBeamPressureProfile'] = 'ring-free-closed-flow-ribbons'
  geometry.userData['pfxWindBeamPressureHeroStreamCount'] = 1
  geometry.userData['pfxWindBeamPressureSecondaryStreamCount'] = 2
  geometry.userData['pfxWindBeamPressureAccentStreamCount'] = 1
  geometry.userData['pfxWindBeamPressureOrganicCurvature'] = true
  geometry.userData['pfxWindBeamPressureAxialRingSuppression'] = true
  geometry.userData['pfxWindBeamPressureEndpointVariation'] = true
  geometry.userData['pfxWindBeamPressureIndependentDepthLanes'] = true
  geometry.userData['pfxWindBeamPressureStreamDepthSlopes'] = streams.map((stream) => stream.depthSlope)
  geometry.userData['pfxWindBeamPressureVerticalOrderPreserved'] = true
  geometry.userData['pfxWindBeamPressureCrossSectionRadius'] = 1.05
  geometry.userData['pfxWindBeamPressureCrossSegments'] = crossSegments
  geometry.userData['pfxWindBeamPressureFlowAxis'] = [1, flowRise, flowDepth]
  geometry.userData['pfxWindBeamPressureAxisAligned'] = true
  geometry.userData['pfxWindBeamPressureArcHeight'] = arcHeight
  geometry.userData['pfxWindBeamPressureMaxAxialDepthDrift'] = 0.93
  geometry.userData['pfxWindBeamPressurePalette'] = 'silver-air-with-seasonal-foliage'
  geometry.userData['pfxWindBeamPressureSideProfileLayerCount'] = 4
  geometry.userData['pfxWindBeamPressureCurvatureProfileCount'] = streams.length
  geometry.userData['pfxWindBeamPressureLaneHierarchy'] = 'hero-secondary-accent'
  geometry.userData['pfxWindBeamPressureHeroWidthMultiplier'] = 1.05
  geometry.userData['pfxWindBeamPressureShellRole'] = 'subordinate-atmosphere'
  geometry.userData['pfxWindBeamPressureSecondaryWidthRange'] = [0.58, 0.7]
  geometry.userData['pfxWindBeamPressureContourGrammar'] = 'four-varied-strands-tail-to-leading-scoop'
  geometry.userData['pfxWindBeamPressureContourValueSteps'] = [1, 0.48, 0.34, 0.2]
  geometry.userData['pfxWindBeamPressureSideProfile'] = 'ordered-axial-cross-section'
  geometry.userData['pfxWindBeamPressureMaxHarmonicDepth'] = Math.max(...harmonicZ.map((value) => Math.abs(value)))
  geometry.userData['pfxWindBeamPressureArcScaleRange'] = Math.max(...arcScales) - Math.min(...arcScales)
  geometry.userData['pfxWindBeamPressureClosedCrossSections'] = true
  geometry.userData['pfxWindBeamPressureRingCount'] = 0
  geometry.userData['pfxWindBeamPressureEndCapCount'] = 0
  geometry.userData['pfxWindBeamPressureHead'] = 'open-leading-scoop'
  geometry.userData['pfxWindBeamPressureVolume'] = 'tail-to-front-gust-envelope'
  geometry.userData['pfxWindBeamPressureHeadTailRadiusRatio'] = 0.54 / 0.24
  geometry.userData['pfxWindBeamPressureGroundWakeCount'] = groundWakeCount
  geometry.userData['pfxWindBeamPressureGroundWakeSections'] = groundWakeSections
  geometry.userData['pfxWindBeamPressureGroundWakeEdgeBreakup'] = true
  geometry.userData['pfxWindBeamPressureGroundWakeAxialMerge'] = true
  geometry.userData['pfxWindBeamPressureCoreTreatment'] = 'striated-translucent-air'
  geometry.userData['pfxWindBeamPressureGroundWakeMaterial'] = 'cool-feathered-air-shear'
  geometry.userData['pfxWindBeamPressureGroundWakeTopology'] = 'folded-feathered-pressure-sheets'
  geometry.userData['pfxWindBeamPressureGroundWakeFlatPlaceholderCount'] = 0
  geometry.userData['pfxWindBeamPressureAxialSupportProfile'] = 'open-directional-slashes'
  geometry.userData['pfxWindBeamPressureTemporalSilhouette'] = 'compressed-surge-scattered-recovery'
  geometry.userData['pfxWindBeamPressureTailConvergenceRatio'] = 0.18
  geometry.userData['pfxWindBeamPressureSingleSided'] = true
  geometry.userData['pfxWindBeamPressureGroundWakeUpwardWinding'] = true
  geometry.userData['pfxWindBeamPressureGroundWakeMaxHalfWidth'] = 0.15
  geometry.userData['pfxWindBeamPressureCompressedOnsetVolume'] = 0.65
  geometry.userData['pfxWindBeamPressurePeakOccupancy'] = 'four-varied-strands-with-integrated-debris'
  geometry.userData['pfxWindBeamPressureRecoveryWispCount'] = 2
  geometry.userData['pfxWindBeamPressureTriangleCount'] = indices.length / 3
  geometry.userData['pfxWindBeamPressureHeightSpan'] = geometry.boundingBox!.max.y - geometry.boundingBox!.min.y
  return geometry
}

export function createPfxWindBeamPressureMaterial(
  opacity: number,
  color: THREE.ColorRepresentation = '#d8fff4',
  secondaryColor: THREE.ColorRepresentation = '#b8e6ff',
  density = 0.58,
  styleEdgeHardness = 0.52,
): THREE.ShaderMaterial {
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uColor: { value: new THREE.Color(color) },
      uSecondaryColor: { value: new THREE.Color(secondaryColor) },
      uOpacity: { value: THREE.MathUtils.clamp(opacity, 0, 1) },
      uCycle: { value: 0 },
      uDensity: { value: THREE.MathUtils.clamp(density, 0, 1) },
      uStyleEdgeHardness: { value: THREE.MathUtils.clamp(styleEdgeHardness, 0, 1) },
    },
    vertexColors: true,
    transparent: true,
    blending: THREE.NormalBlending,
    depthWrite: false,
    depthTest: true,
    side: THREE.FrontSide,
    toneMapped: false,
    vertexShader: `
      uniform float uCycle;
      varying vec3 vColor;
      varying vec3 vNormal;
      varying vec3 vViewDirection;
      varying vec2 vUv;
      void main() {
        vColor = color;
        vUv = uv;
        float compressReach = mix(0.28, 0.78, smoothstep(0.0, 0.06, uCycle));
        float surgeRelease = smoothstep(0.06, 0.08, uCycle);
        float lifecycleReach = mix(compressReach, 1.0, surgeRelease);
        float travelFront = -1.94 + 4.0 * lifecycleReach;
        float recoveryScatter = smoothstep(0.14, 0.34, uCycle) * (1.0 - smoothstep(0.4, 0.42, uCycle));
        float groundWakeVertex = step(9.0, uv.y);
        float airborneVertex = 1.0 - groundWakeVertex;
        float lanePhase = floor(uv.y) * 1.83 + uv.x * 4.2;
        vec3 transformed = position;
        transformed.x = -1.94 + (position.x + 1.94) * lifecycleReach;
        transformed.x = min(transformed.x, travelFront);
        float onsetVolume = mix(0.65, 1.0, lifecycleReach);
        transformed.y *= mix(onsetVolume, 1.0, groundWakeVertex);
        transformed.z *= mix(onsetVolume, 1.0, groundWakeVertex);
        transformed.x += recoveryScatter * airborneVertex * (0.06 + uv.x * 0.2);
        transformed.y += recoveryScatter * airborneVertex * sin(lanePhase) * (0.08 + uv.x * 0.22);
        transformed.z += recoveryScatter * airborneVertex * cos(lanePhase * 0.87) * (0.07 + uv.x * 0.19);
        float groundContactLift = -groundWakeVertex * recoveryScatter * 0.025;
        transformed.y += groundContactLift;
        vec4 viewPosition = modelViewMatrix * vec4(transformed, 1.0);
        vNormal = normalize(normalMatrix * normal);
        vViewDirection = normalize(-viewPosition.xyz);
        gl_Position = projectionMatrix * viewPosition;
      }
    `,
    fragmentShader: `
      uniform vec3 uColor;
      uniform vec3 uSecondaryColor;
      uniform float uOpacity;
      uniform float uCycle;
      uniform float uDensity;
      uniform float uStyleEdgeHardness;
      varying vec3 vColor;
      varying vec3 vNormal;
      varying vec3 vViewDirection;
      varying vec2 vUv;
      void main() {
        float facing = abs(dot(normalize(vNormal), normalize(vViewDirection)));
        float mobileFastRim = 1.0 - facing;
        float rim = mobileFastRim * (0.5 + mobileFastRim * 0.5);
        float pressureRibbon = 0.54 + facing * 0.46;
        float heroRibbon = 1.0 - step(1.0, vUv.y);
        float streamLane = floor(vUv.y);
        float secondaryLuminanceFloor = mix(0.58, 0.72, uDensity);
        float secondaryOrder = mix(secondaryLuminanceFloor, secondaryLuminanceFloor * 0.78, step(1.5, streamLane));
        secondaryOrder = mix(secondaryOrder, secondaryLuminanceFloor * 0.56, step(2.5, streamLane));
        float laneHierarchy = mix(secondaryOrder, 1.0, heroRibbon);
        float heroFlowDominance = mix(0.82, 1.18, heroRibbon);
        float laneContrast = 0.84 + 0.16 * (sin(streamLane * 2.37 + 0.8) * 0.5 + 0.5);
        float strandRimHighlight = mobileFastRim * mobileFastRim;
        float strandKeyHighlight = abs(dot(normalize(vNormal), normalize(vec3(0.34, 0.82, 0.46))));
        float strandVolumeLight = 0.7 + 0.3 * strandKeyHighlight;
        float strandDepthContrast = 0.92 + 0.08 * (sin(streamLane * 1.71 + 0.4) * 0.5 + 0.5);
        float laneTemperature = sin(streamLane * 1.91 + 0.6) * 0.5 + 0.5;
        float groundWake = step(9.0, vUv.y);
        float gustShell = step(8.0, vUv.y) * (1.0 - groundWake);
        float turbulenceBand = 0.72 + 0.28 * smoothstep(0.2, 0.92, sin(vUv.x * 31.0 + vUv.y * 13.0));
        float tipSoftFade = 1.0 - smoothstep(0.72, 0.98, vUv.x);
        float flowFade = smoothstep(0.0, 0.08, vUv.x) * tipSoftFade;
        float smoothFacetResponse = smoothstep(0.08, 0.94, facing);
        float facet = 0.78 + 0.22 * smoothFacetResponse;
        float shellFacetBand = smoothstep(0.12, 0.88, facing);
        float shellSector = fract(vUv.y);
        float shellSectorBreakup = smoothstep(0.08, 0.2, shellSector) * (1.0 - smoothstep(0.62, 0.88, shellSector));
        float axialRingSuppression = 0.06 + shellSectorBreakup * 0.94;
        float groundCrest = sin(clamp((vUv.x - 0.12) / 0.72, 0.0, 1.0) * 3.1415927);
        float groundCross = fract(vUv.y);
        float groundStriation = 0.72 + 0.28 * sin(vUv.x * 28.0 + groundCross * 11.0);
        float directionalFlowWindow = mix(0.28, 1.0, smoothstep(0.04, 0.92, vUv.x));
        float leadingPressureCrest = smoothstep(0.48, 0.82, vUv.x) * (1.0 - smoothstep(0.92, 1.0, vUv.x));
        float anticipationGlow = 1.0 - smoothstep(0.02, 0.07, uCycle);
        float organicStreamBreakup = 0.74 + 0.26 * smoothstep(0.12, 0.88, sin(vUv.x * 23.0 + streamLane * 2.7) * 0.5 + 0.5);
        float ribbonStriation = sin(vUv.x * 27.0 + vUv.y * 9.0) * 0.5 + 0.5;
        float fineAirStreaks = 0.76 + 0.24 * (sin(vUv.x * 53.0 + streamLane * 4.7) * 0.5 + 0.5);
        float airTurbulenceTexture = fineAirStreaks * (0.84 + 0.16 * (sin(vUv.x * 17.0 - vUv.y * 15.0) * 0.5 + 0.5));
        float anticipationVisibility = mix(1.72, 1.0, smoothstep(0.02, 0.08, uCycle));
        float strandSpecularBase = smoothstep(0.54, 1.0, facing);
        float strandSpecular = strandSpecularBase * strandSpecularBase * (0.72 + ribbonStriation * 0.28);
        float turbulentRibbon = 0.72 + 0.28 * ribbonStriation;
        float energyFalloff = smoothstep(0.0, 0.7, max(0.0, sin(vUv.x * 3.1415927)));
        float ribbonInteriorGradient = 0.28 + 0.72 * pow(max(0.0, sin(fract(vUv.y) * 3.1415927)), 0.72);
        float motionBlurHighlight = smoothstep(0.0, 0.62, max(0.0, sin(vUv.x * 3.1415927))) * (0.78 + ribbonStriation * 0.22);
        float airShearBase = 1.0 - ribbonInteriorGradient;
        float airShearEdge = airShearBase * airShearBase * (0.7 + strandRimHighlight * 0.3);
        float heroBladeSuppression = 0.82 + ribbonStriation * 0.18;
        vec3 neutralAirGradient = mix(vec3(0.52, 0.59, 0.63), vec3(0.94, 0.97, 0.98), smoothstep(0.08, 0.86, vUv.x));
        vec3 desaturatedSkyGradient = neutralAirGradient;
        vec3 longitudinalColor = desaturatedSkyGradient;
        vec3 controlledPressureColor = mix(uSecondaryColor, uColor, 0.62 + heroRibbon * 0.2);
        vec3 ribbonBase = mix(mix(vColor, longitudinalColor, 0.12), controlledPressureColor, 0.62 + ribbonStriation * 0.1);
        vec3 ribbonHighlight = mix(longitudinalColor, controlledPressureColor, 0.84);
        vec3 ribbonColor = mix(ribbonBase, ribbonHighlight, ribbonInteriorGradient * 0.52) * (0.76 + pressureRibbon * 0.24 + heroRibbon * 0.08) * facet * turbulentRibbon * laneContrast * strandVolumeLight * strandDepthContrast * heroFlowDominance;
        ribbonColor = mix(ribbonColor * vec3(0.92, 0.98, 1.03), ribbonColor * vec3(1.04, 1.0, 0.91), laneTemperature * 0.22);
        float heroCrestHighlight = heroRibbon * ribbonInteriorGradient * ribbonInteriorGradient * (0.74 + energyFalloff * 0.26);
        ribbonColor += mix(vec3(0.48, 0.74, 0.78), controlledPressureColor, 0.72) * strandRimHighlight * (0.08 + heroRibbon * 0.14);
        ribbonColor += mix(vec3(0.86, 0.97, 1.0), controlledPressureColor, 0.56) * strandSpecular * (0.2 + heroRibbon * 0.08);
        ribbonColor += vec3(0.94, 0.98, 1.0) * strandKeyHighlight * (0.1 + heroRibbon * 0.04);
        ribbonColor += vec3(0.72, 0.92, 0.94) * heroCrestHighlight * 0.08;
        ribbonColor += vec3(1.0, 0.96, 0.8) * motionBlurHighlight * (0.08 + heroRibbon * 0.035);
        ribbonColor += vec3(0.9, 0.86, 0.72) * airShearEdge * 0.07;
        ribbonColor += mix(vColor, uColor, 0.68) * energyFalloff * (0.035 + heroRibbon * 0.055);
        ribbonColor += vec3(0.62, 0.9, 0.94) * leadingPressureCrest * (0.18 + strandRimHighlight * 0.12);
        ribbonColor += vec3(0.46, 0.72, 0.76) * anticipationGlow * (0.12 + strandRimHighlight * 0.08);
        float recoveryWispPhase = smoothstep(0.14, 0.22, uCycle) * (1.0 - smoothstep(0.36, 0.42, uCycle));
        float recoveryWispPattern = sin(vUv.x * 19.0 + streamLane * 3.7 + uCycle * 13.0) * 0.5 + 0.5;
        float recoveryWisp = recoveryWispPhase * smoothstep(0.48, 0.78, recoveryWispPattern);
        ribbonColor += vec3(0.7, 0.9, 0.94) * recoveryWisp * (0.14 + strandRimHighlight * 0.08);
        ribbonColor *= mix(2.08, 2.28, uDensity) * airTurbulenceTexture;
        vec3 shellColor = mix(vColor, controlledPressureColor, 0.64) * (0.72 + shellFacetBand * 0.58 + rim * 0.2) * turbulenceBand * 1.24;
        float groundDustLift = 0.18 + groundCrest * 0.2;
        float featheredGroundShear = smoothstep(0.02, 0.3, groundCross) * (1.0 - smoothstep(0.7, 0.98, groundCross));
        vec3 groundColor = mix(uSecondaryColor * 0.34, controlledPressureColor * 0.72, 0.38 + facing * 0.28) * (0.86 + groundDustLift) * groundStriation;
        vec3 shaded = mix(ribbonColor, shellColor, gustShell);
        shaded = mix(shaded, groundColor, groundWake);
        float ribbonAlpha = flowFade * directionalFlowWindow * organicStreamBreakup * (0.68 + pressureRibbon * 0.52 + leadingPressureCrest * 0.18 + anticipationGlow * 0.2) * turbulentRibbon * airTurbulenceTexture * laneHierarchy * anticipationVisibility;
        ribbonAlpha *= mix(1.0, heroBladeSuppression * 0.94, heroRibbon);
        ribbonAlpha += recoveryWisp * flowFade * (0.16 + heroRibbon * 0.1);
        float shellFade = smoothstep(0.0, 0.12, vUv.x) * (1.0 - smoothstep(0.72, 1.0, vUv.x));
        float axialViewWeight = smoothstep(0.62, 0.92, mobileFastRim);
        float axialDirectionalSlash = smoothstep(0.14, 0.24, shellSector) * (1.0 - smoothstep(0.42, 0.56, shellSector)) * smoothstep(0.46, 0.72, vUv.x);
        float axialPortalSuppression = mix(0.38, axialDirectionalSlash * 0.55, axialViewWeight);
        float axialDirectionalVane = axialViewWeight * axialDirectionalSlash * flowFade;
        float axialVolumeRim = strandRimHighlight * 0.38 * shellSectorBreakup;
        float subordinateShell = 0.052 + facing * 0.08 + axialVolumeRim;
        float shellAlpha = min(0.014, shellFade * directionalFlowWindow * (subordinateShell + leadingPressureCrest * 0.055 + anticipationGlow * 0.035 + recoveryWisp * 0.08) * turbulenceBand * axialRingSuppression * axialPortalSuppression) + axialDirectionalVane * 0.34;
        float groundEdgeFade = featheredGroundShear * (0.68 + 0.32 * (1.0 - abs(groundCross - 0.5) * 2.0));
        float groundAlpha = min(0.16, (0.12 + facing * 0.035 + groundDustLift * 0.06) * directionalFlowWindow * groundEdgeFade * groundStriation * tipSoftFade);
        float recoveryPhase = smoothstep(0.14, 0.23, uCycle) * (1.0 - smoothstep(0.36, 0.42, uCycle));
        float laneWiseRecovery = floor(vUv.y) * 2.13;
        float recoveryDissolve = sin(vUv.x * 21.0 + laneWiseRecovery + uCycle * 11.0) * 0.5 + 0.5;
        float frayBreakup = smoothstep(recoveryPhase * 0.62 - 0.16, recoveryPhase * 0.62 + 0.28, recoveryDissolve);
        float cleanDecayEnvelope = 0.74 + frayBreakup * 0.26;
        float recoveryEnvelope = mix(1.0, cleanDecayEnvelope, recoveryPhase);
        float alpha = mix(ribbonAlpha, shellAlpha, gustShell);
        alpha = mix(alpha, groundAlpha, groundWake);
        alpha *= recoveryEnvelope;
        gl_FragColor = vec4(shaded, uOpacity * alpha);
      }
    `,
  })
  material.userData['pfxWindBeamPressureMaterial'] = true
  material.userData['pfxWindBeamPressureMaterialProfile'] = 'crisp-hero-over-quiet-shell'
  material.userData['pfxWindBeamPressureLuminanceFloor'] = 1.34
  material.userData['pfxWindBeamPressureContrastBoost'] = 2.28
  material.userData['pfxWindBeamPressureHeroAlphaFloor'] = 0.68
  material.userData['pfxWindBeamPressureDirectionalGradientRatio'] = 3.57
  material.userData['pfxWindBeamPressureMotionHighlight'] = true
  material.userData['pfxWindBeamPressureAxialRimBoost'] = 0.38
  material.userData['pfxWindBeamPressureGroundOpacityCap'] = 0.16
  material.userData['pfxWindBeamPressureShellOpacityCap'] = 0.012
  material.userData['pfxWindBeamPressureHeroSecondaryAlphaRatio'] = 2.08
  material.userData['pfxWindBeamPressureGroundDustContrast'] = 1.56
  material.userData['pfxWindBeamPressureAxialVaneOpacity'] = 0.34
  material.userData['pfxWindBeamPressureAnticipationBoost'] = 1.72
  material.userData['pfxWindBeamPressureAxialPortalSuppression'] = true
  material.userData['pfxWindBeamPressureGroundMaterialProfile'] = 'feathered-cool-air-shear'
  material.userData['pfxWindBeamPressureControlBinding'] = 'primary-secondary-density-style'
  material.userData['pfxWindBeamPressureControlTintStrength'] = 0.64
  return material
}

export function applyPfxWindBeamPressureMaterialAppearance(
  material: THREE.ShaderMaterial,
  opacity: number,
  cycle: number,
): void {
  const opacityUniform = material.uniforms['uOpacity']
  if (opacityUniform) opacityUniform.value = THREE.MathUtils.clamp(opacity, 0, 1)
  const cycleUniform = material.uniforms['uCycle']
  if (cycleUniform) cycleUniform.value = ((cycle % 1) + 1) % 1
}

